import { useChartContext } from "@/contexts/ChartContext";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useStandardChartController } from "@/hooks/useChartController";
import { useChartFiltersSync } from "@/hooks/useChartFiltersSync";
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from "@/util/carbon-chart-base";
import {
  fetchStablecoinRatio,
  type InferFetcherData,
} from "@/services/chart/chartApi";
import type { StablecoinRatioRequestParams } from "@/types/chart-api.types";
import {
  formatTimestampWithTimezone,
  isChartSuccess,
} from "@/util/chart-helpers";
import { formatAxisTooltip } from "@/util/tooltip-helpers";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo, useRef } from "react";
import { ChartWrapper, ChartContainer, ChartGridItem, ChartSection, ChartStatsHeader } from "../shared";
import type { ChartProps } from "../shared/ChartProp";
import type { StatCard } from "../shared/ChartStatsHeader";

type StablecoinTooltipParam = { value: [number, number] };

type StablecoinRatioData = InferFetcherData<typeof fetchStablecoinRatio>;

export function StablecoinRatioChart({
  title,
  minHeight = 400,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
  autoRefresh = true,
  refreshInterval = 30000,
  fetchEnabled = true,
  actions,
}: ChartProps) {
  const { tr } = useLocalization();
  const chartTitle = title || tr("charts.stablecoinRatioChart.title");

  const chartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();
  const { selectedTimezone: timezone } = useChartContext();

  const { filters, walletsString } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  const query = useMemo<StablecoinRatioRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
    }),
    [filters.timePeriod, walletsString],
  );

  const { data, loadingState, refetch } = useStandardChartController<
    StablecoinRatioData,
    StablecoinRatioRequestParams
  >({
    fetcher: fetchStablecoinRatio,
    query,
    autoRefresh,
    refreshInterval,
    enabled: fetchEnabled,
  });

  const chartOption = useMemo((): EChartsOption | null => {
    const base = baseOption;

    if (!isChartSuccess(data, "wallets")) return null;

    const series = data.wallets.map((wallet, index) => {
      const color =
        CHART_COLOR_PALETTE[index % CHART_COLOR_PALETTE.length];

      return {
        name: wallet.walletName || wallet.walletAddress,
        type: "line" as const,
        data: wallet.data.map((d) => [d.timestamp, d.value]),
        smooth: true,
        lineStyle: {
          color: color,
          width: 2,
        },
        itemStyle: {
          color: color,
        },
        symbol: "circle" as const,
        symbolSize: 6,
        showSymbol: false,
        emphasis: {
          focus: "series" as const,
          showSymbol: true,
        },
      };
    });

    return {
      ...base,
      xAxis: {
        ...base.xAxis,
        type: "time",
        axisLabel: {
          ...base.xAxis.axisLabel,
          formatter: (value: number) =>
            formatTimestampWithTimezone(value, timezone, "MM/dd"),
        },
      },
      yAxis: {
        ...base.yAxis,
        type: "value",
        name: "Stablecoin Ratio (%)",
        min: 0,
        max: 100,
        axisLabel: {
          ...base.yAxis.axisLabel,
          formatter: "{value}%",
        },
      },
      series: series,
      legend: {
        show: true,
        data: data.wallets.map((w) => w.walletAddress),
        textStyle: { color: base.textStyle.color },
      },
      tooltip: {
        ...base.tooltip,
        trigger: "axis",
        axisPointer: {
          type: "cross",
        },
        formatter: (params: unknown) =>
          formatAxisTooltip(
            params,
            (p) =>
              formatTimestampWithTimezone(
                p.value[0],
                timezone,
                "yyyy-MM-dd HH:mm",
              ),
            (p) => `${p.value[1].toFixed(2)}%`,
          ),
      },
    };
  }, [data, baseOption, timezone]);

  const statsCards = useMemo<StatCard[]>(() => {
    if (!isChartSuccess(data, "wallets") || data.wallets.length === 0)
      return [];

    return data.wallets.map((wallet) => ({
      title: wallet.walletName || wallet.walletAddress,
      stats: [
        {
          label: "Current Ratio",
          value: wallet.currentRatio?.toFixed(2) || "-",
          suffix: "%",
        },
        {
          label: "Average Ratio",
          value: wallet.averageRatio?.toFixed(2) || "-",
          suffix: "%",
        },
      ],
    }));
  }, [data]);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={!isChartSuccess(data, "wallets") || data.wallets.length === 0}
      onRetry={() => refetch(false)}
      actions={actions}
    >
      <ChartContainer>
        <ChartStatsHeader cards={statsCards} minColumnWidth="200px" />
        <ChartSection minHeight={`${minHeight}px`}>
          {chartOption && (
            <ChartGridItem minHeight={minHeight}>
              <ReactECharts
                ref={chartRef}
                option={chartOption}
                style={{
                  height: "100%",
                  width: "100%",
                  minHeight: `${minHeight}px`,
                }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          )}
        </ChartSection>
      </ChartContainer>
    </ChartWrapper>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { useCarbonTokens } from "@/hooks/useCarbonToken";
import { cds } from "@/util/carbon-theme";
import { InlineLoading, Stack } from "@carbon/react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo } from "react";

// Add your specific usecase here and help yourself
export type TimeSeriesChartHelper = "average-buy-sell";

export interface TimeSeriesDataPoint {
  unixTimeMs: number;
  value: number;
}

export interface MarkLineConfig {
  value: number;
  label: string;
  color?: string;
}

export interface TimeSeriesChartProps {
  data: TimeSeriesDataPoint[] | undefined;
  markLines?: MarkLineConfig[];
  loading?: boolean;
  isDataSorted?: boolean;
  title?: string;
  height?: number | string;
  className?: string;
  helper?: TimeSeriesChartHelper;
  valueFormatter?: (val: number | null) => string;
}

export function TimeSeriesLineChart({
  data,
  markLines = [],
  loading = false,
  isDataSorted = false,
  title,
  helper,
  height = 300,
  className,
  valueFormatter,
}: TimeSeriesChartProps) {
  const { fmt, tr } = useLocalization();

  const tokens = useCarbonTokens({
    textPrimary: cds.textPrimary,
    textSecondary: cds.textSecondary,
    textHelper: cds.textHelper,
    bgInverse: cds.backgroundInverse,
    textInverse: cds.textInverse,
    success: cds.supportSuccess,
    error: cds.supportError,
    borderSubtle: cds.borderSubtle00,
    // Default color for markLines
    interactive: cds.interactive,
  });

  const chartData = useMemo(() => {
    if (!data || data.length == 0) return [];
    const sorted = isDataSorted
      ? data
      : [...data].sort((a, b) => a.unixTimeMs - b.unixTimeMs);
    return sorted.map((p) => [p.unixTimeMs, p.value]);
  }, [data, isDataSorted]);

  const isPositive = useMemo(() => {
    if (chartData.length < 2) return true;
    return chartData[chartData.length - 1][1] >= chartData[0][1];
  }, [chartData]);

  const option = useMemo((): EChartsOption => {
    if (chartData.length == 0) return {};

    const trendColor = isPositive ? tokens.success : tokens.error;
    const startTime = chartData[0][0];
    const endTime = chartData[chartData.length - 1][0];
    const range = endTime - startTime;

    return {
      backgroundColor: "transparent",
      title: {
        text: title,
        left: "center",
        textStyle: { fontSize: 14, fontWeight: 600, color: tokens.textPrimary },
      },
      grid: { left: 10, right: 10, top: 40, bottom: 30, containLabel: true },
      tooltip: {
        trigger: "axis",
        backgroundColor: tokens.bgInverse,
        borderColor: "transparent",
        borderRadius: 4,
        padding: 0,
        textStyle: { color: tokens.textInverse, fontSize: 12 },
        formatter: (params) => {
          if (!Array.isArray(params) || !params[0]) return "";
          // only casting we need
          const [ts, val] = params[0].data as [number, number];
          const dateStr =
            range < 86_400_000 * 2
              ? fmt.datetime.datetime(ts)
              : fmt.datetime.date(ts);
          const valStr = valueFormatter ? valueFormatter(val) : val;

          return `
            <div style="padding:8px 12px; border-radius:4px; background:${tokens.bgInverse}">
              <div style="color:${tokens.textInverse}; opacity:0.7; margin-bottom:4px; font-size:11px">${dateStr}</div>
              <div style="font-size:14px; font-weight:700; color:${tokens.textInverse}">${valStr}</div>
            </div>`;
        },
      },
      xAxis: {
        type: "time",
        axisLine: { show: true },
        axisTick: { show: true },
        // Suggest a reasonable number of splits for a 300px-ish height chart
        // splitNumber: 8,
        // Prevent ticks from being too close together
        // minInterval: 3600 * 1000 * 24, // 1 day ms
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          // Use hideOverlap to automatically remove clashing labels
          hideOverlap: true,
          formatter: (val) => {
            // If the total range is > 30 days, just show Month/Day
            if (range > 86_400_000 * 30) {
              return fmt.datetime.date(val);
            }
            // If < 24h, show Time
            if (range < 86_400_000) {
              return fmt.datetime.time(val);
            }
            // Default fallback
            return fmt.datetime.date(val);
          },
        },
        splitLine: {
          show: true,
          lineStyle: {
            color: tokens.borderSubtle,
            type: "dashed",
            width: 1,
          },
        },
      },
      yAxis: {
        type: "value",
        scale: true,
        position: "right",
        axisLine: { show: false },
        axisTick: { show: false },
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          formatter: (val) => fmt.num.compact.currency(val),
        },
        splitLine: {
          lineStyle: { color: tokens.borderSubtle, type: "dashed" },
        },
        min: (value) => {
          let min = value.min;
          markLines.forEach((ml) => {
            if (ml.value < min) min = ml.value;
          });
          const spread = value.max - value.min || min * 0.1;
          return min - spread * 0.15; // 15% buffer based on spread
        },
        max: (value) => {
          let max = value.max;
          markLines.forEach((ml) => {
            if (ml.value > max) max = ml.value;
          });
          const spread = value.max - value.min || max * 0.1;
          return max + spread * 0.15;
        },
      },
      series: [
        {
          type: "line",
          data: chartData,
          showSymbol: false,
          smooth: 0.1,
          lineStyle: { width: 2, color: trendColor },
          areaStyle: {
            color: {
              type: "linear",
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: trendColor },
                { offset: 1, color: "transparent" },
              ],
            },
            opacity: 0.15,
          },
          markLine: {
            // Important: Default is 2. For tokens, we need high precision.
            precision: 8,
            lineStyle: {
              width: 1,
              opacity: 0.8,
            },
            data: markLines.map((ml, index) => ({
              name: ml.label,
              yAxis: ml.value,
              lineStyle: { color: ml.color || tokens.interactive },
              label: {
                formatter: () =>
                  `${ml.label}: ${valueFormatter ? valueFormatter(ml.value) : ml.value}`,
                position:
                  helper == "average-buy-sell" && markLines.length == 2
                    ? ml.value > markLines.at(index - 1)!.value
                      ? "insideEndTop"
                      : "insideEndBottom"
                    : "insideEndBottom",
                backgroundColor: ml.color,
                padding: [4, 4],
              },
            })),
          },
        },
      ],
    };
  }, [chartData, isPositive, title, fmt, valueFormatter, tokens, markLines]);

  if (loading)
    return (
      <Stack style={{ height, alignItems: "center", justifyContent: "center" }}>
        <InlineLoading description={tr("common.loading")} />
      </Stack>
    );

  if (chartData.length == 0)
    return (
      <div
        style={{
          height,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: tokens.textHelper,
        }}
      >
        {tr("common.noData")}
      </div>
    );

  return (
    <div className={className}>
      <ReactECharts
        option={option}
        style={{ height }}
        notMerge
        opts={{ renderer: "canvas" }}
      />
    </div>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { useCarbonTokens } from "@/hooks/useCarbonToken";
import { cds } from "@/util/carbon-theme";
import { InlineLoading, Stack } from "@carbon/react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useMemo } from "react";

export interface TimeSeriesDataPoint {
  unixTimeMs: number;
  value: number;
}

export interface MarkLineConfig {
  value: number;
  label: string;
  color?: string;
}

export interface TradePoint {
  unixTimeMs: number;
  side: "buy" | "sell";
  volumeUsd: number;
  price: number | null;
  priceSource: "trade" | "mapped" | "missing";
  transactionHash?: string;
}

export interface TradeAggregationConfig {
  timeBucketMs: number;
}

export interface TimeSeriesTradesScatterChartProps {
  data: TimeSeriesDataPoint[] | undefined;
  trades: TradePoint[];
  markLines?: MarkLineConfig[];
  loading?: boolean;
  isDataSorted?: boolean;
  title?: string;
  height?: number | string;
  className?: string;
  valueFormatter?: (val: number | null) => string;
  aggregation?: TradeAggregationConfig;
}

interface TradeBucket {
  buyCount: number;
  sellCount: number;
  buyVolumeUsd: number;
  sellVolumeUsd: number;
  midpointMs: number;
  matchedPrice: number;
}

interface MarkPointDataItem {
  name: string;
  coord: [number, number];
  value: string;
  itemStyle: { color: string };
  symbol: string;
  symbolSize: number;
  label: { show: false } | {
    show: true;
    formatter: string;
    position: "inside";
    fontSize: number;
    fontWeight: "bold";
    color: string;
  };
}

const DEFAULT_AGGREGATION: TradeAggregationConfig = {
  timeBucketMs: 60 * 60 * 1000,
};

function toFiniteNumber(value: unknown): number | null {
  if (typeof value !== "number") {
    return null;
  }
  if (!Number.isFinite(value)) {
    return null;
  }
  return value;
}

function normalizeMarketData(
  marketData: TimeSeriesDataPoint[] | undefined,
  isDataSorted: boolean,
): TimeSeriesDataPoint[] {
  if (!marketData || marketData.length === 0) {
    return [];
  }

  if (isDataSorted) {
    return marketData;
  }

  return [...marketData].sort((a, b) => a.unixTimeMs - b.unixTimeMs);
}

export function findNearestMarketPrice(
  marketData: TimeSeriesDataPoint[],
  targetUnixTimeMs: number,
): number | null {
  if (!marketData.length) {
    return null;
  }

  if (targetUnixTimeMs <= marketData[0].unixTimeMs) {
    return marketData[0].value;
  }

  const last = marketData[marketData.length - 1];
  if (targetUnixTimeMs >= last.unixTimeMs) {
    return last.value;
  }

  let left = 0;
  let right = marketData.length - 1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    const midTs = marketData[mid].unixTimeMs;

    if (midTs === targetUnixTimeMs) {
      return marketData[mid].value;
    }

    if (midTs < targetUnixTimeMs) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  const leftPoint = marketData[left];
  const rightPoint = marketData[right];

  if (!leftPoint) {
    return rightPoint?.value ?? null;
  }

  if (!rightPoint) {
    return leftPoint.value;
  }

  const leftDistance = Math.abs(leftPoint.unixTimeMs - targetUnixTimeMs);
  const rightDistance = Math.abs(rightPoint.unixTimeMs - targetUnixTimeMs);

  return leftDistance < rightDistance ? leftPoint.value : rightPoint.value;
}

export function mapTradesWithFallbackPrice(
  trades: TradePoint[],
  marketData: TimeSeriesDataPoint[] | undefined,
  isMarketDataSorted = false,
): TradePoint[] {
  const sortedMarketData = normalizeMarketData(marketData, isMarketDataSorted);

  return trades.map((trade) => {
    const directPrice = toFiniteNumber(trade.price);
    if (directPrice !== null) {
      return {
        ...trade,
        price: directPrice,
        priceSource: "trade",
      };
    }

    const mappedPrice = findNearestMarketPrice(
      sortedMarketData,
      trade.unixTimeMs,
    );

    if (mappedPrice === null) {
      return {
        ...trade,
        price: null,
        priceSource: "missing",
      };
    }

    return {
      ...trade,
      price: mappedPrice,
      priceSource: "mapped",
    };
  });
}

export function buildTradeBuckets(
  trades: TradePoint[],
  marketData: TimeSeriesDataPoint[],
  startTime: number,
  endTime: number,
  bucketSizeMs: number,
): Map<number, TradeBucket> {
  const bucketMap = new Map<number, TradeBucket>();

  for (const t of trades) {
    if (t.unixTimeMs < startTime || t.unixTimeMs > endTime) {
      continue;
    }

    const volumeUsd = toFiniteNumber(t.volumeUsd);
    if (volumeUsd === null || volumeUsd <= 0) {
      continue;
    }

    const bucketIdx = Math.floor((t.unixTimeMs - startTime) / bucketSizeMs);
    const existing = bucketMap.get(bucketIdx);

    if (existing) {
      if (t.side === "buy") {
        existing.buyCount += 1;
        existing.buyVolumeUsd += volumeUsd;
      } else {
        existing.sellCount += 1;
        existing.sellVolumeUsd += volumeUsd;
      }
    } else {
      const bucketStart = startTime + bucketIdx * bucketSizeMs;
      bucketMap.set(bucketIdx, {
        buyCount: t.side === "buy" ? 1 : 0,
        sellCount: t.side === "sell" ? 1 : 0,
        buyVolumeUsd: t.side === "buy" ? volumeUsd : 0,
        sellVolumeUsd: t.side === "sell" ? volumeUsd : 0,
        midpointMs: bucketStart + bucketSizeMs / 2,
        matchedPrice:
          findNearestMarketPrice(marketData, t.unixTimeMs) ?? t.price ?? 0,
      });
    }
  }

  return bucketMap;
}

function buildMarkPointData(
  bucketMap: Map<number, TradeBucket>,
  minPrice: number,
  maxPrice: number,
  buyLabel: string,
  sellLabel: string,
): MarkPointDataItem[] {
  const priceRange = maxPrice - minPrice || 1;
  const offset = priceRange * 0.12;
  const highThreshold = maxPrice - priceRange * 0.2;
  const result: MarkPointDataItem[] = [];

  for (const bucket of bucketMap.values()) {
    const { buyCount, sellCount, midpointMs, matchedPrice } = bucket;
    const isTooHigh = matchedPrice > highThreshold;

    if (buyCount > 0 && sellCount === 0) {
      const y = isTooHigh
        ? matchedPrice - offset * 1.5
        : matchedPrice + offset * 1.5;
      result.push({
        name: buyLabel,
        coord: [midpointMs, y],
        value: String(buyCount),
        itemStyle: { color: "#24a148" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
    } else if (sellCount > 0 && buyCount === 0) {
      const y = isTooHigh
        ? matchedPrice - offset * 1.5
        : matchedPrice + offset * 1.5;
      result.push({
        name: sellLabel,
        coord: [midpointMs, y],
        value: String(sellCount),
        itemStyle: { color: "#da1e28" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
    } else if (buyCount > 0 && sellCount > 0) {
      const buyY = isTooHigh
        ? matchedPrice - offset
        : matchedPrice + offset * 2;
      const sellY = isTooHigh
        ? matchedPrice - offset * 2
        : matchedPrice + offset;
      result.push({
        name: buyLabel,
        coord: [midpointMs, buyY],
        value: String(buyCount),
        itemStyle: { color: "#24a148" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
      result.push({
        name: sellLabel,
        coord: [midpointMs, sellY],
        value: String(sellCount),
        itemStyle: { color: "#da1e28" },
        symbol: "circle",
        symbolSize: 10,
        label: { show: false },
      });
    }
  }

  return result;
}

export function getDefaultAggregationForDayRange(
  days: "7" | "30" | "90",
): TradeAggregationConfig {
  if (days === "7") {
    return { timeBucketMs: 60 * 60 * 1000 };
  }

  if (days === "30") {
    return { timeBucketMs: 4 * 60 * 60 * 1000 };
  }

  return { timeBucketMs: 12 * 60 * 60 * 1000 };
}

export function TimeSeriesTradesScatterChart({
  data,
  trades,
  markLines = [],
  loading = false,
  isDataSorted = false,
  title,
  height = 300,
  className,
  valueFormatter,
  aggregation = DEFAULT_AGGREGATION,
}: TimeSeriesTradesScatterChartProps) {
  const { fmt, tr } = useLocalization();

  const tokens = useCarbonTokens({
    textPrimary: cds.textPrimary,
    textSecondary: cds.textSecondary,
    textHelper: cds.textHelper,
    bgInverse: cds.backgroundInverse,
    textInverse: cds.textInverse,
    success: cds.supportSuccess,
    error: cds.supportError,
    borderSubtle: cds.borderSubtle00,
    interactive: cds.interactive,
    warning: cds.supportWarning,
  });

  const chartData = useMemo(() => {
    if (!data || data.length === 0) {
      return [] as [number, number][];
    }

    const sorted = isDataSorted
      ? data
      : [...data].sort((a, b) => a.unixTimeMs - b.unixTimeMs);

    return sorted.map(
      (point) => [point.unixTimeMs, point.value] as [number, number],
    );
  }, [data, isDataSorted]);

  const normalizedMarketData = useMemo(
    () => normalizeMarketData(data, isDataSorted),
    [data, isDataSorted],
  );

  const hasChartContent = chartData.length > 0;

  const option = useMemo((): EChartsOption => {
    if (!hasChartContent) {
      return {};
    }

    const startTime = chartData[0][0];
    const endTime = chartData[chartData.length - 1][0];
    const range = Math.max(1, endTime - startTime);

    const trendColor =
      chartData.length >= 2 &&
      chartData[chartData.length - 1][1] >= chartData[0][1]
        ? tokens.success
        : tokens.error;

    const bucketSizeMs = 24 * 60 * 60 * 1000;
    const bucketMap = buildTradeBuckets(
      trades,
      normalizedMarketData,
      startTime,
      endTime,
      bucketSizeMs,
    );

    const allPrices = chartData.map((d) => d[1]);
    const minPrice = Math.min(...allPrices);
    const maxPrice = Math.max(...allPrices);

    const markPointData = buildMarkPointData(
      bucketMap,
      minPrice,
      maxPrice,
      tr("walletPage.buy"),
      tr("walletPage.sell"),
    );

    return {
      backgroundColor: "transparent",
      title: {
        text: title,
        left: "center",
        textStyle: {
          fontSize: 14,
          fontWeight: 600,
          color: tokens.textPrimary,
        },
      },
      grid: { left: 10, right: 10, top: 40, bottom: 30, containLabel: true },
      tooltip: {
        trigger: "item",
        backgroundColor: tokens.bgInverse,
        borderColor: "transparent",
        borderRadius: 4,
        padding: 0,
        textStyle: { color: tokens.textInverse, fontSize: 12 },
        formatter: (params) => {
          if (!params) {
            return "";
          }

          const singleParams = Array.isArray(params) ? params[0] : params;
          const raw = singleParams as unknown as Record<string, unknown>;
          const componentType = raw.componentType as string | undefined;

          if (componentType === "markPoint") {
            const data = raw.data as {
              coord?: [number, number];
              name?: string;
            } | undefined;
            if (!data?.coord) {
              return "";
            }

            const ts = data.coord[0];
            const dateStr =
              range < 86_400_000 * 2
                ? fmt.datetime.datetime(ts)
                : fmt.datetime.date(ts);

            const bucketIdx = Math.floor((ts - startTime) / bucketSizeMs);
            const bucket = bucketMap.get(bucketIdx);

            const isSell = data.name === tr("walletPage.sell");
            const sideLabel = isSell ? tr("walletPage.sell") : tr("walletPage.buy");
            const sideLabelLower = sideLabel.toLowerCase();
            const count = isSell ? bucket?.sellCount : bucket?.buyCount;
            const volume = isSell ? bucket?.sellVolumeUsd : bucket?.buyVolumeUsd;

            let tradeInfo = "";
            if (count && count > 0) {
              tradeInfo = `<div style="font-size:12px;margin-top:4px">${count} ${sideLabelLower}${count > 1 ? "s" : ""}</div><div style="font-size:11px;opacity:0.8;margin-top:2px">${fmt.num.compact.currency(volume ?? 0)}</div>`;
            }

            return `
              <div style="padding:8px 12px">
                <div style="opacity:0.7;font-size:11px;margin-bottom:4px">${dateStr}</div>
                <div style="display:flex;align-items:center;gap:6px;font-size:13px;font-weight:600;text-transform:uppercase;margin-bottom:4px">
                  ${raw.marker as string ?? ""}${sideLabel}
                </div>
                ${tradeInfo}
              </div>`;
          }

          const data = raw.data as [number, number] | undefined;
          if (!data) {
            return "";
          }

          const ts = data[0];
          const price = data[1];
          const dateStr =
            range < 86_400_000 * 2
              ? fmt.datetime.datetime(ts)
              : fmt.datetime.date(ts);
          const valStr = valueFormatter
            ? valueFormatter(price)
            : fmt.num.compact.currency(price);

          const bucketIdx = Math.floor((ts - startTime) / bucketSizeMs);
          const bucket = bucketMap.get(bucketIdx);

          let tradeInfo = "";
          if (bucket && (bucket.buyCount > 0 || bucket.sellCount > 0)) {
            const parts: string[] = [];
            if (bucket.buyCount > 0) {
              const label = tr("walletPage.buy").toLowerCase();
              parts.push(
                `${bucket.buyCount} ${label}${bucket.buyCount > 1 ? "s" : ""}`,
              );
            }
            if (bucket.sellCount > 0) {
              const label = tr("walletPage.sell").toLowerCase();
              parts.push(
                `${bucket.sellCount} ${label}${bucket.sellCount > 1 ? "s" : ""}`,
              );
            }
            const totalVolume = bucket.buyVolumeUsd + bucket.sellVolumeUsd;
            tradeInfo = `<div style="font-size:11px;margin-top:4px;opacity:0.8">${parts.join(", ")} · ${fmt.num.compact.currency(totalVolume)}</div>`;
          }

          return `
            <div style="padding:8px 12px">
              <div style="opacity:0.7;font-size:11px;margin-bottom:2px">${dateStr}</div>
              <div style="font-size:14px;font-weight:700">${valStr}</div>
              ${tradeInfo}
            </div>`;
        },
      },
      xAxis: {
        type: "time",
        axisLine: { show: false },
        axisTick: { show: false },
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          hideOverlap: true,
          formatter: (val: number) => {
            if (range > 86_400_000 * 30) {
              return fmt.datetime.date(val);
            }
            if (range < 86_400_000) {
              return fmt.datetime.time(val);
            }
            return fmt.datetime.date(val);
          },
        },
        splitLine: { show: false },
      },
      yAxis: {
        type: "value",
        scale: true,
        position: "right",
        axisLine: { show: false },
        axisTick: { show: false },
        axisLabel: {
          color: tokens.textSecondary,
          fontSize: 11,
          formatter: (val: number) => fmt.num.compact.currency(val),
        },
        splitLine: {
          lineStyle: { color: tokens.borderSubtle, type: "dashed" },
        },
        min: (value) => {
          let min = value.min;
          markLines.forEach((markLine) => {
            if (markLine.value < min) {
              min = markLine.value;
            }
          });
          const spread =
            value.max - value.min || Math.max(Math.abs(min) * 0.1, 1);
          return min - spread * 0.15;
        },
        max: (value) => {
          let max = value.max;
          markLines.forEach((markLine) => {
            if (markLine.value > max) {
              max = markLine.value;
            }
          });
          const spread =
            value.max - value.min || Math.max(Math.abs(max) * 0.1, 1);
          return max + spread * 0.15;
        },
      },
      series: [
        {
          type: "line",
          data: chartData,
          showSymbol: false,
          smooth: 0.1,
          lineStyle: { width: 2, color: trendColor },
          areaStyle: {
            color: {
              type: "linear",
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: trendColor },
                { offset: 1, color: "transparent" },
              ],
            },
            opacity: 0.12,
          },
          markPoint: {
            data: markPointData,
            symbolOffset: [0, 0],
            label: { show: true },
          },
          markLine: {
            precision: 8,
            lineStyle: {
              width: 1,
              opacity: 0.8,
            },
            data: markLines.map((markLine) => ({
              name: markLine.label,
              yAxis: markLine.value,
              lineStyle: { color: markLine.color || tokens.interactive },
              label: {
                formatter: () =>
                  `${markLine.label}: ${valueFormatter ? valueFormatter(markLine.value) : markLine.value}`,
                position:
                  markLines.length === 2
                    ? markLine.value >
                      (markLines[0] === markLine
                        ? markLines[1].value
                        : markLines[0].value)
                      ? "insideEndTop"
                      : "insideEndBottom"
                    : "insideEndBottom",
                backgroundColor: markLine.color,
                padding: [4, 4],
              },
            })),
          },
          z: 1,
        },
      ],
    };
  }, [
    chartData,
    trades,
    normalizedMarketData,
    aggregation,
    tokens,
    fmt,
    tr,
    valueFormatter,
    title,
    markLines,
    hasChartContent,
  ]);

  if (loading) {
    return (
      <Stack style={{ height, alignItems: "center", justifyContent: "center" }}>
        <InlineLoading description={tr("common.loading")} />
      </Stack>
    );
  }

  if (!hasChartContent) {
    return (
      <div
        style={{
          height,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: tokens.textHelper,
        }}
      >
        {tr("common.noData")}
      </div>
    );
  }

  return (
    <div className={className}>
      <ReactECharts
        option={option}
        style={{ height }}
        notMerge
        opts={{ renderer: "canvas" }}
      />
    </div>
  );
}

import { useLocalization } from "@/contexts/LocalizationContext";
import { fetchTokenPriceChartForDay, type TokenPriceChartPoint } from "@/services/wallet/walletApi";
import { useCarbonChartBaseOption, CHART_COLOR_PALETTE } from "@/util/carbon-chart-base";
import { Close } from "@carbon/icons-react";
import type { EChartsOption } from "echarts";
import ReactECharts from "echarts-for-react";
import { useEffect, useMemo, useState } from "react";
import styles from "./TokenPriceChart.module.scss";
import { Flex } from "@/components/Flex";
import { Txt } from "@/components/Txt";

export interface TradeIndicator {
  timestampMs: number;
  type: "buy" | "sell";
  price: number;
  amount: number;
  symbol: string;
}

interface AggregatedTradeBucket {
  buyCount: number;
  sellCount: number;
  buyTotalAmount: number;
  sellTotalAmount: number;
  midpointMs: number;
  matchedPrice: number;
}

interface TokenPriceChartProps {
  tokenAddress: string;
  tokenSymbol: string;
  tokenLogoUri: string | null;
  dayMs: number;
  trades: TradeIndicator[];
  onRemove: () => void;
  priceHistory?: TokenPriceChartPoint[];
}

function formatUtcTime(val: number): string {
  const d = new Date(val);
  const h = String(d.getUTCHours()).padStart(2, "0");
  const m = String(d.getUTCMinutes()).padStart(2, "0");
  return `${h}:${m}`;
}

export function TokenPriceChart({
  tokenAddress,
  tokenSymbol,
  tokenLogoUri,
  dayMs,
  trades,
  onRemove,
  priceHistory: priceHistoryProp,
}: TokenPriceChartProps) {
  const { fmt, tr } = useLocalization();
  const baseOption = useCarbonChartBaseOption();

  const [priceData, setPriceData] = useState<TokenPriceChartPoint[]>(priceHistoryProp ?? []);
  const [loading, setLoading] = useState(!priceHistoryProp);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (priceHistoryProp) {
      setPriceData(priceHistoryProp);
      setLoading(false);
      return;
    }

    let cancelled = false;
    setLoading(true);
    setError(null);

    fetchTokenPriceChartForDay(tokenAddress, dayMs)
      .then((res) => {
        if (!cancelled) {
          setPriceData(res.items);
          setLoading(false);
        }
      })
      .catch((err) => {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : "Failed to load price data");
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [tokenAddress, dayMs, priceHistoryProp]);

  const chartOption = useMemo((): EChartsOption => {
    if (priceData.length === 0) return {};

    const sorted = [...priceData].sort((a, b) => a.timestampMs - b.timestampMs);
    const chartData = sorted.map((p) => [p.timestampMs, p.price]);


    const startTime = dayMs;

    const allPrices = chartData.map((d) => d[1] as number);
    const minPrice = Math.min(...allPrices);
    const maxPrice = Math.max(...allPrices);
    const priceRange = maxPrice - minPrice || 1;

    const color = CHART_COLOR_PALETTE[0];

    function findClosestPrice(timestampMs: number): number {
      let closest = sorted[0];
      let minDiff = Math.abs(sorted[0].timestampMs - timestampMs);
      for (let i = 1; i < sorted.length; i++) {
        const diff = Math.abs(sorted[i].timestampMs - timestampMs);
        if (diff < minDiff) {
          minDiff = diff;
          closest = sorted[i];
        }
      }
      return closest.price;
    }

    const bucketSizeMs = 15 * 60 * 1000;
    const bucketMap = new Map<number, AggregatedTradeBucket>();

    for (const t of trades) {
      const bucketIdx = Math.floor((t.timestampMs - startTime) / bucketSizeMs);
      const existing = bucketMap.get(bucketIdx);
      if (existing) {
        if (t.type === "buy") {
          existing.buyCount += 1;
          existing.buyTotalAmount += t.amount;
        } else {
          existing.sellCount += 1;
          existing.sellTotalAmount += t.amount;
        }
      } else {
        const bucketStart = startTime + bucketIdx * bucketSizeMs;
        bucketMap.set(bucketIdx, {
          buyCount: t.type === "buy" ? 1 : 0,
          sellCount: t.type === "sell" ? 1 : 0,
          buyTotalAmount: t.type === "buy" ? t.amount : 0,
          sellTotalAmount: t.type === "sell" ? t.amount : 0,
          midpointMs: bucketStart + bucketSizeMs / 2,
          matchedPrice: findClosestPrice(t.timestampMs),
        });
      }
    }

    const offset = priceRange * 0.06;
    const highThreshold = maxPrice - priceRange * 0.2;

    const markPointData: Array<{
      name: string;
      coord: [number, number];
      value: string;
      itemStyle: { color: string };
      symbol: string;
      symbolSize: number;
      label: { show: boolean; formatter: string; position: "inside"; fontSize: number; fontWeight: "bold"; color: string };
    }> = [];

    for (const bucket of bucketMap.values()) {
      const { buyCount, sellCount, midpointMs, matchedPrice } = bucket;
      const isTooHigh = matchedPrice > highThreshold;

      if (buyCount > 0 && sellCount === 0) {
        const y = isTooHigh ? matchedPrice - offset * 1.5 : matchedPrice + offset * 1.5;
        markPointData.push({
          name: tr("walletPage.buy"),
          coord: [midpointMs, y],
          value: "",
          itemStyle: { color: "#24a148" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
      } else if (sellCount > 0 && buyCount === 0) {
        const y = isTooHigh ? matchedPrice - offset * 1.5 : matchedPrice + offset * 1.5;
        markPointData.push({
          name: tr("walletPage.sell"),
          coord: [midpointMs, y],
          value: "",
          itemStyle: { color: "#da1e28" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
      } else if (buyCount > 0 && sellCount > 0) {
        const buyY = isTooHigh ? matchedPrice - offset : matchedPrice + offset * 2;
        const sellY = isTooHigh ? matchedPrice - offset * 2 : matchedPrice + offset;
        markPointData.push({
          name: tr("walletPage.buy"),
          coord: [midpointMs, buyY],
          value: String(buyCount),
          itemStyle: { color: "#24a148" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
        markPointData.push({
          name: tr("walletPage.sell"),
          coord: [midpointMs, sellY],
          value: String(sellCount),
          itemStyle: { color: "#da1e28" },
          symbol: "circle",
          symbolSize: 10,
          label: { show: true, formatter: "{c}", position: "inside", fontSize: 9, fontWeight: "bold", color: "#fff" },
        });
      }
    }

    return {
      ...baseOption,
      legend: { show: false },
      grid: { left: 8, right: 8, top: 8, bottom: 24 },
      xAxis: {
        ...baseOption.xAxis,
        type: "time",
        boundaryGap: false as never,
        splitNumber: 4,
        axisLabel: {
          ...baseOption.xAxis?.axisLabel,
          formatter: (val: number) => formatUtcTime(val),
          fontSize: 10,
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "value",
        position: "right" as const,
        axisLabel: {
          ...baseOption.yAxis?.axisLabel,
          formatter: (val: number) => fmt.num.compact.currency(val),
          fontSize: 10,
        },
        min: (v: { min: number; max: number }) => v.min - (v.max - v.min) * 0.15,
        max: (v: { min: number; max: number }) => v.max + (v.max - v.min) * 0.15,
      },
      tooltip: {
        ...baseOption.tooltip,
        trigger: "axis",
        formatter: (params) => {
          if (!Array.isArray(params) || params.length === 0) return "";

          const ts = (params[0].data as [number, number])[0];
          const price = (params[0].data as [number, number])[1];
          const dateStr = formatUtcTime(ts);

          const bucketIdx = Math.floor((ts - startTime) / bucketSizeMs);
          const bucket = bucketMap.get(bucketIdx);

          let tradeInfo = "";
          if (bucket && (bucket.buyCount > 0 || bucket.sellCount > 0)) {
            const parts: string[] = [];
            if (bucket.buyCount > 0) {
              parts.push(`${bucket.buyCount} ${bucket.buyCount === 1 ? tr("walletPage.buy").toLowerCase() : tr("walletPage.buy").toLowerCase() + "s"}`);
            }
            if (bucket.sellCount > 0) {
              parts.push(`${bucket.sellCount} ${bucket.sellCount === 1 ? tr("walletPage.sell").toLowerCase() : tr("walletPage.sell").toLowerCase() + "s"}`);
            }
            const totalAmount = bucket.buyTotalAmount + bucket.sellTotalAmount;
            tradeInfo = `<div style="font-size:11px;margin-top:4px;">${parts.join(", ")} · ${fmt.num.decimal(totalAmount)} ${trades[0]?.symbol ?? ""}</div>`;
          }

          return `
            <div style="padding:4px 0">
              <div style="opacity:0.7;font-size:11px">${dateStr}</div>
              <div style="font-size:13px"><strong>${fmt.num.currency(price)}</strong></div>
              ${tradeInfo}
            </div>`;
        },
      },
      series: [
        {
          name: tokenSymbol,
          type: "line",
          data: chartData,
          showSymbol: false,
          smooth: false,
          lineStyle: { width: 2, color },
          itemStyle: { color },
          areaStyle: {
            color: {
              type: "linear",
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: `${color}4D` },
                { offset: 1, color: `${color}0D` },
              ],
            },
          },
          markPoint: {
            data: markPointData,
            symbolOffset: [0, 0],
            label: {
              show: true,
            },
          },
        },
      ],
    };
  }, [priceData, trades, tokenSymbol, fmt, tr, baseOption]);

  if (loading) {
    return (
      <div className={styles.chartCard}>
        <div className={styles.chartHeader}>
          <div className={styles.tokenInfo}>
            {tokenLogoUri && (
              <img src={tokenLogoUri} alt={tokenSymbol} className={styles.tokenImg} />
            )}
            <span className={styles.tokenSymbol}>{tokenSymbol}</span>
          </div>
        </div>
        <div className={styles.chartContent}>
          <Flex justify="center" align="center" p={2}>
            <Txt size="sm" secondary>{tr("common.loading")}</Txt>
          </Flex>
        </div>
      </div>
    );
  }

  if (error || priceData.length === 0) {
    return (
      <div className={styles.chartCard}>
        <div className={styles.chartHeader}>
          <div className={styles.tokenInfo}>
            {tokenLogoUri && (
              <img src={tokenLogoUri} alt={tokenSymbol} className={styles.tokenImg} />
            )}
            <span className={styles.tokenSymbol}>{tokenSymbol}</span>
          </div>
          <button className={styles.removeBtn} onClick={onRemove} aria-label={tr("common.cancel")}>
            <Close size={16} />
          </button>
        </div>
        <div className={styles.chartContent}>
          <Flex justify="center" align="center" p={3}>
            <Txt size="sm" secondary>{error ?? tr("common.noData")}</Txt>
          </Flex>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.chartCard}>
      <div className={styles.chartHeader}>
        <div className={styles.tokenInfo}>
          {tokenLogoUri && (
            <img src={tokenLogoUri} alt={tokenSymbol} className={styles.tokenImg} />
          )}
          <span className={styles.tokenSymbol}>{tokenSymbol}</span>
        </div>
        <button className={styles.removeBtn} onClick={onRemove} aria-label={tr("common.cancel")}>
          <Close size={16} />
        </button>
      </div>
      <div className={styles.chartContent}>
        <ReactECharts
          option={chartOption}
          style={{ height: 180, width: "100%" }}
          notMerge
          lazyUpdate
          opts={{ renderer: "canvas" }}
        />
      </div>
    </div>
  );
}

import React, { useMemo, useRef, useCallback, useState, useEffect } from 'react';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import type { EChartsInstance } from '@/util/echarts-setup';
import { useLocalization } from '@/contexts/LocalizationContext';
import { useChartFiltersSync } from '@/hooks/useChartFiltersSync';
import { PeriodSelector } from '@/components/common/PeriodSelector/PeriodSelector';
import { useCarbonChartBaseOption } from '@/util/carbon-chart-base';
import { useCarbonTokens } from '@/hooks/useCarbonToken';
import { cds } from '@/util/carbon-theme';
import { useChartContext } from '@/contexts/ChartContext';
import { fetchTradingVolumeDistribution, type InferFetcherData } from '@/services/chart/chartApi';
import { isChartSuccess } from '@/util/chart-helpers';
import { createTooltipHeader, createTooltipRow } from '@/util/tooltip-helpers';
import type { TradingVolumeDistributionRequestParams } from '@/types/chart-api.types';
import { useStandardChartController } from '@/hooks/useChartController';
import { ChartWrapper, ChartGrid, ChartGridItem } from '@/components/charts/shared';
import { useChartExport } from '@/hooks/useChartExport';
import type { ExportFormat } from '@/types/chart-filters.types';
import type { ChartDataSeries } from '@/types/chart-data.types';
import type { ChartProps } from '../shared/ChartProp';
import { runChartExport } from '@/services/chart/chartExportService';

type TradingVolumeDistributionData = InferFetcherData<typeof fetchTradingVolumeDistribution>;
const DEFAULT_BUY_COLOR = '#24a148';
const DEFAULT_SELL_COLOR = '#da1e28';

type TradingVolumeWallet = {
  wallet?: string;
  walletAddress: string;
  buyVolume?: number;
  sellVolume?: number;
  totalVolume?: number;
};

type PieTooltipParam = {
  name: string;
  value?: unknown;
  data: { percentage: number };
};

export const TradingVolumeDistribution: React.FC<ChartProps> = ({
  minHeight = 400,
  initialFilters,
  autoRefresh = true,
  refreshInterval = 30000,
  fetchEnabled = true,
  className,
  actions,
}) => {
  const { tr, fmt } = useLocalization();
  const chartTitle = tr('charts.tradingVolumeDistributionChart.title');
  const buyLabel = tr('charts.tradingVolumeDistributionChart.buy');
  const sellLabel = tr('charts.tradingVolumeDistributionChart.sell');

  const chartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();
  const tradeColors = useCarbonTokens({
    buy: cds.supportSuccess,
    sell: cds.supportError,
  });
  const { selectedTimezone: timezone } = useChartContext();

  const [selectedAssets, setSelectedAssets] = useState<Set<string>>(new Set());

  const { filters, walletsString, setTimePeriod } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  const query = useMemo<TradingVolumeDistributionRequestParams>(
    () => ({
      period: filters.timePeriod,
      wallets: walletsString,
    }),
    [filters.timePeriod, walletsString]
  );

  const { data, loadingState, refetch } =
    useStandardChartController<TradingVolumeDistributionData, TradingVolumeDistributionRequestParams>({
      fetcher: fetchTradingVolumeDistribution,
      query,
      autoRefresh,
      refreshInterval,
      enabled: fetchEnabled,
    });

  const { exportPNG, exportSVG, exportPDF, exportCSV } = useChartExport({
    chartTitle,
    timezone,
    baseFilename: 'trading-volume-distribution',
  });

  const handleExport = useCallback(
    async (format: ExportFormat) => {
      if (!isChartSuccess(data, 'wallets')) return;
      if (!data.wallets || !Array.isArray(data.wallets) || data.wallets.length === 0) return;

      const instance = chartRef.current?.getEchartsInstance() ?? null;
      const csv: ChartDataSeries[] = [];

      if (data.wallets && Array.isArray(data.wallets)) {
        data.wallets.forEach((wallet: TradingVolumeWallet) => {
          const buy = wallet.buyVolume ?? 0;
          const sell = wallet.sellVolume ?? 0;
          csv.push({
            id: `trading-volume-distribution-${wallet.wallet}`,
            name: `Trading Volume Distribution - ${wallet.wallet}`,
            type: 'pie',
            visible: true,
            data: [
              { name: buyLabel, value: buy },
              { name: sellLabel, value: sell },
            ],
          });
        });
      }

      await runChartExport(
        {
          format,
          filters,
          chartInstance: instance as EChartsInstance | null,
          csvData: csv,
        },
        { exportPNG, exportSVG, exportPDF, exportCSV }
      );
    },
    [data, filters, exportPNG, exportSVG, exportPDF, exportCSV]
  );

  const createChartOption = useCallback((
    distributionData: { name: string; value: number; percentage: number; color?: string }[],
    total: number,
    walletLabel?: string,
    isMultiWallet?: boolean
  ): EChartsOption => {
    const filteredData = isMultiWallet && selectedAssets.size > 0
      ? distributionData.filter(a => selectedAssets.has(a.name))
      : distributionData;

    const filteredTotal = filteredData.reduce((sum, a) => sum + a.value, 0);
    const dataWithRecalculatedPercentages = filteredData.map(a => ({
      ...a,
      percentage: filteredTotal > 0 ? (a.value / filteredTotal) * 100 : 0,
    }));

    return {
      ...baseOption,
      xAxis: undefined,
      yAxis: undefined,
      title: walletLabel ? {
        text: walletLabel,
        left: 8,
        top: 8,
        textStyle: {
          color: baseOption.textStyle.color,
          fontSize: 16,
          fontWeight: 'bold',
        },
      } : undefined,
      tooltip: {
        ...baseOption.tooltip,
        trigger: 'item',
        formatter: (param: unknown) => {
          const p = param as PieTooltipParam;
          return createTooltipHeader(p.name)
            + createTooltipRow(
              tr('charts.tradingVolumeDistributionChart.volume'),
              fmt.num.compact.currency(Number(p.value ?? 0))
            )
            + createTooltipRow(
              tr('charts.tradingVolumeDistributionChart.percentage'),
              `${p.data.percentage.toFixed(2)}%`
            );
        },
      },
      legend: {
        show: true,
        data: distributionData.map(d => d.name),
        textStyle: { color: baseOption.textStyle.color },
      },
      series: [
        {
          type: 'pie',
          radius: ['22%', '48%'],
          center: ['50%', '50%'],
          data: dataWithRecalculatedPercentages.map((a) => ({
            name: a.name,
            value: a.value,
            percentage: a.percentage,
            itemStyle: {
              color: a.color,
              borderColor: baseOption.backgroundColor as string,
              borderWidth: 2,
              borderRadius: 6,
            },
          })),
          label: {
            formatter: (param: unknown) => { const p = param as PieTooltipParam; return `${p.name}\n${p.data.percentage.toFixed(1)}%`; },
            fontSize: 11,
          },
        },
      ],
      graphic: [
        {
          type: 'text',
          left: 'center',
          top: '46%',
          style: {
            text: tr('charts.tradingVolumeDistributionChart.totalVolume'),
            fill: baseOption.textStyle.color,
            fontSize: 14,
          },
        },
        {
          type: 'text',
          left: 'center',
          top: '50%',
          style: {
            text: fmt.num.compact.currency(isMultiWallet && selectedAssets.size > 0 ? filteredTotal : total),
            fill: baseOption.textStyle.color,
            fontSize: 18,
            fontWeight: 'bold',
          },
        },
      ],
    };
  }, [baseOption, tr, selectedAssets, fmt]);

  const aggregatedLegendData = useMemo(() => {
    if (!data || !data.wallets || !Array.isArray(data.wallets) || data.wallets.length <= 1) return null;
    const buyColor = tradeColors.buy || DEFAULT_BUY_COLOR;
    const sellColor = tradeColors.sell || DEFAULT_SELL_COLOR;

    return [
      {
        name: buyLabel,
        color: buyColor,
      },
      {
        name: sellLabel,
        color: sellColor,
      },
    ];
  }, [data, buyLabel, sellLabel, tradeColors]);

  useEffect(() => {
    if (aggregatedLegendData) {
      setSelectedAssets(new Set(aggregatedLegendData.map(a => a.name)));
    }
  }, [aggregatedLegendData]);

  const toggleAssetSelection = useCallback((assetName: string) => {
    setSelectedAssets(prev => {
      const newSet = new Set(prev);
      if (newSet.has(assetName)) {
        if (newSet.size > 1) {
          newSet.delete(assetName);
        }
      } else {
        newSet.add(assetName);
      }
      return newSet;
    });
  }, []);

  const chartOptions = useMemo(() => {
    if (!data || !data.wallets || !Array.isArray(data.wallets) || data.wallets.length === 0 || (data.wallets as unknown as { error?: unknown }).error) return [];

    const isMultiWallet = data.wallets.length > 1;

    return data.wallets.map((wallet) => {
      const buy = wallet.buyVolume ?? 0;
      const sell = wallet.sellVolume ?? 0;
      const total = wallet.totalVolume ?? (buy + sell);
      const buyColor = tradeColors.buy || DEFAULT_BUY_COLOR;
      const sellColor = tradeColors.sell || DEFAULT_SELL_COLOR;
      const pieData = [
        { name: buyLabel, value: buy, percentage: total > 0 ? (buy / total) * 100 : 0, color: buyColor },
        { name: sellLabel, value: sell, percentage: total > 0 ? (sell / total) * 100 : 0, color: sellColor },
      ];
      return {
        walletAddress: wallet.walletAddress,
        option: createChartOption(
          pieData,
          total,
          `${wallet.walletAddress.slice(0, 8)}...`,
          isMultiWallet
        ),
      };
    });
  }, [data, createChartOption, buyLabel, sellLabel, tradeColors]);

  const isEmpty = !isChartSuccess(data, 'wallets') || data.wallets.length === 0 || (filters.wallets && filters.wallets.length === 0);

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      isEmpty={isEmpty}
      emptyState={filters.wallets && filters.wallets.length === 0
        ? {
          title: tr('charts.tradingVolumeDistributionChart.noWalletsTitle'),
          message: tr('charts.tradingVolumeDistributionChart.noWalletsMessage'),
        }
        : undefined}
      onRetry={() => refetch(false)}
      onExport={handleExport}
      className={className}
      actions={actions}
    >
      <div data-html2canvas-ignore="true" style={{ padding: '0.5rem' }}>
        <PeriodSelector value={filters.timePeriod} onChange={(k) => setTimePeriod(k)} compact />
      </div>

      {chartOptions.length > 0 && (
        <div style={{ display: 'flex', flexDirection: 'column', width: '100%' }}>
          {aggregatedLegendData && chartOptions.length > 1 && (
            <div
              data-html2canvas-ignore="true"
              style={{
                display: 'flex',
                flexWrap: 'wrap',
                gap: '1rem',
                padding: '1rem',
                justifyContent: 'center',
                borderBottom: '1px solid var(--cds-border-subtle)',
                marginBottom: '1rem',
              }}
            >
              {aggregatedLegendData.map((asset) => {
                const isSelected = selectedAssets.has(asset.name);
                return (
                  <div
                    key={asset.name}
                    onClick={() => toggleAssetSelection(asset.name)}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: '0.5rem',
                      cursor: 'pointer',
                      opacity: isSelected ? 1 : 0.3,
                      transition: 'opacity 0.2s ease',
                      userSelect: 'none',
                    }}
                    title={isSelected ? `Click to hide ${asset.name}` : `Click to show ${asset.name}`}
                  >
                    <span
                      style={{
                        width: '12px',
                        height: '12px',
                        borderRadius: '50%',
                        backgroundColor: asset.color,
                        opacity: isSelected ? 1 : 0.5,
                      }}
                    />
                    <span style={{ fontSize: '14px', color: baseOption.textStyle.color }}>
                      {asset.name}
                    </span>
                  </div>
                );
              })}
            </div>
          )}

          <ChartGrid itemCount={chartOptions.length} multiItemColumns={3}>
            {chartOptions.map((chartData, index) => (
              <ChartGridItem
                key={chartData.walletAddress}
                itemKey={chartData.walletAddress}
                minHeight={minHeight}
                aspectRatio="1"
              >
                <ReactECharts
                  ref={index === 0 ? chartRef : undefined}
                  option={chartData.option}
                  style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
                  notMerge
                  lazyUpdate
                />
              </ChartGridItem>
            ))}
          </ChartGrid>
        </div>
      )}
    </ChartWrapper>
  );
};

import { useMemo, useRef, useState } from 'react';
import ReactECharts from 'echarts-for-react';
import { useLocalization } from '@/contexts/LocalizationContext';
import { ChartWrapper, ChartGridItem } from '@/components/charts/shared';
import { useChartFiltersSync } from '@/hooks/useChartFiltersSync';
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from '@/util/carbon-chart-base';
import { useChartContext } from '@/contexts/ChartContext';
import { fetchTransactionDistribution, type InferFetcherData } from '@/services/chart/chartApi';
import { formatDate, isChartSuccess } from '@/util/chart-helpers';
import { formatAxisTooltip } from '@/util/tooltip-helpers';
import type { TransactionDistributionRequestParams } from '@/types/chart-api.types';

type TransactionDistributionData = InferFetcherData<typeof fetchTransactionDistribution>;

type AxisPoint = {
  value: [number, number];
  color?: string;
  seriesName?: string;
};
import type { TimePeriod, TransactionType } from '@/types/chart-filters.types';
import { useStandardChartController } from '@/hooks/useChartController';
import { Flex } from '@/components/Flex';
import { FilterSwitch } from '@/components/FilterSwitch';

interface TransactionDistributionProps {
  title?: string;
  minHeight?: number;
  initialTimePeriod?: TimePeriod;
  initialTransactionType?: TransactionType;
  chartMode?: 'stacked' | 'grouped';
  walletIds?: string[];
  autoRefresh?: boolean;
  refreshInterval?: number;
  onDataLoaded?: (data: TransactionDistributionData) => void;
  className?: string;
}

export function TransactionDistribution({
  title,
  minHeight = 400,
  initialTimePeriod = '30D',
  initialTransactionType = 'all',
  chartMode = 'stacked',
  walletIds = [],
  autoRefresh = true,
  refreshInterval = 30000,
  onDataLoaded,
}: TransactionDistributionProps) {
  const { tr } = useLocalization();
  const chartTitle = title || tr('charts.transactionDistributionChart.title');

  const [selectedChartMode, setSelectedChartMode] = useState<'stacked' | 'grouped'>(chartMode);

  const transactionChartRef = useRef<ReactECharts>(null);
  const tokenChartRef = useRef<ReactECharts>(null);

  const { selectedTimezone: timezone } = useChartContext();
  const baseOption = useCarbonChartBaseOption();

  const { filters, walletsString } = useChartFiltersSync({
    initialFilters: {
      timePeriod: initialTimePeriod,
      transactionType: initialTransactionType,
      wallets: walletIds.length > 0 ? walletIds : undefined,
    },
    debounceDelay: 300,
  });

  const query = useMemo<TransactionDistributionRequestParams>(
    () => ({
      timePeriod: filters.timePeriod,
      transactionType: filters.transactionType,
      walletIds: walletsString,
      timezone,
    }),
    [filters.timePeriod, filters.transactionType, walletsString, timezone]
  );

  const { data, loadingState, refetch } =
    useStandardChartController<TransactionDistributionData, TransactionDistributionRequestParams>({
      fetcher: fetchTransactionDistribution,
      query,
      autoRefresh,
      refreshInterval,
      onDataLoaded,
    });

  const transactionCountsOptions = useMemo(() => {
    if (!isChartSuccess(data, 'transactionCounts')) {
      return {};
    }

    const series = data.transactionCounts.map((wallet, index) => ({
      name: wallet.walletName,
      type: 'bar' as const,
      stack: selectedChartMode === 'stacked' ? 'total' : undefined,
      data: wallet.data.map(point => [point.timestamp, point.value]),
      label: {
        show: wallet.data.length <= 30,
        position: selectedChartMode === 'stacked' ? 'inside' : 'top',
        formatter: (params: any) => {
          const value = params.value[1];
          return value > 0 ? value.toString() : '';
        },
        fontSize: 10,
      },
      color: CHART_COLOR_PALETTE[index % CHART_COLOR_PALETTE.length],
      emphasis: {
        focus: 'series',
      },
    }));

    return {
      ...baseOption,
      tooltip: {
        ...baseOption.tooltip,
        trigger: 'axis',
        axisPointer: {
          type: 'shadow',
        },
        formatter: (params: unknown) => {
          const points = Array.isArray(params) ? (params as AxisPoint[]) : [];
          if (points.length === 0) return '';

          const timestamp = points[0].value[0];
          const dateStr = formatDate(new Date(timestamp), timezone);

          let tooltipContent = `<strong>${dateStr}</strong><br/>`;
          let total = 0;

          points.forEach((param) => {
            const count = param.value[1];
            total += count;
            const color = param.color;
            tooltipContent += `
              <div style="display: flex; align-items: center; margin-top: 4px;">
                <span style="display: inline-block; width: 10px; height: 10px; background-color: ${color}; margin-right: 8px; border-radius: 50%;"></span>
                <span style="flex: 1;">${param.seriesName}:</span>
                <strong style="margin-left: 8px;">${count}</strong>
              </div>
            `;
          });

          if (selectedChartMode === 'stacked') {
            tooltipContent += `<div style="margin-top: 8px; padding-top: 4px; border-top: 1px solid #ccc;"><strong>Total: ${total}</strong></div>`;
          }

          return tooltipContent;
        },
      },
      legend: {
        show: true,
        data: data.transactionCounts.map(w => w.walletName),
        textStyle: { color: baseOption.textStyle.color },
      },
      xAxis: {
        ...baseOption.xAxis,
        type: 'time',
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          formatter: (value: number) => formatDate(new Date(value), timezone, 'MMM dd'),
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: 'value',
        name: 'Transaction count',
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: (value: number) => value.toFixed(0),
        },
      },
      series,
      dataZoom: [
        {
          type: 'inside',
          start: 0,
          end: 100,
        },
        {
          type: 'slider',
          show: data.transactionCounts[0]?.data.length > 50,
          start: 0,
          end: 100,
          height: 20,
          bottom: 10,
        },
      ],
    };
  }, [data, selectedChartMode, timezone, baseOption]);

  const uniqueTokenCountsOptions = useMemo(() => {
    if (!isChartSuccess(data, 'transactionCounts')) {
      return {};
    }

    return {
      ...baseOption,
      tooltip: {
        trigger: 'axis',
        axisPointer: {
          type: 'cross',
          crossStyle: {
            color: '#999',
          },
        },
        formatter: (params: unknown) => formatAxisTooltip(
          params,
          (p) => formatDate(new Date(p.value[0]), timezone),
          (p) => p.value[1].toString()
        ),
      },
      xAxis: {
        ...baseOption.xAxis,
        type: 'time',
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          formatter: (value: number) => formatDate(new Date(value), timezone, 'MMM dd'),
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: 'value',
        name: 'Unique token traded',
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: (value: number) => value.toFixed(0),
        },
      },
      series: [
        {
          name: tr('charts.transactionDistributionChart.tokens'),
          type: 'line',
          data: data.uniqueTokenCounts.map(point => [point.timestamp, point.value]),
          smooth: 0.3,
          showSymbol: data.uniqueTokenCounts.length <= 50,
          symbolSize: 6,
          itemStyle: {
            color: CHART_COLOR_PALETTE[1],
          },
          areaStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: `${CHART_COLOR_PALETTE[1]}4D` },
                { offset: 1, color: `${CHART_COLOR_PALETTE[1]}0D` },
              ],
            },
          },
          label: {
            show: data.uniqueTokenCounts.length <= 30,
            position: 'top',
            formatter: (param: unknown) => (param as AxisPoint).value[1].toString(),
            fontSize: 10,
          },
        },
      ],
      dataZoom: [
        {
          type: 'inside',
          start: 0,
          end: 100,
        },
        {
          type: 'slider',
          show: data.uniqueTokenCounts.length > 50,
          start: 0,
          end: 100,
          height: 20,
          bottom: 10,
        },
      ],
    };
  }, [data, timezone, baseOption, tr]);

  const handleChartModeChange = (mode: 'stacked' | 'grouped') => {
    setSelectedChartMode(mode);
  };

  const handleRetry = () => {
    refetch(false);
  };

  const chartModeOptions = [
    { value: 'stacked' as const, label: tr('charts.transactionDistributionChart.stacked') },
    { value: 'grouped' as const, label: tr('charts.transactionDistributionChart.grouped') },
  ];

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={loadingState}
      onRetry={handleRetry}
      isEmpty={!isChartSuccess(data, 'transactionCounts') || (data.transactionCounts.length === 0 && data.uniqueTokenCounts.length === 0)}
      toolbarLayout="stacked"
      actions={
        <Flex gap={8} align="center">
          <div style={{ width: 160 }}>
            <FilterSwitch
              options={chartModeOptions}
              value={selectedChartMode}
              onChange={(v) => handleChartModeChange(v as 'stacked' | 'grouped')}
            />
          </div>
        </Flex>
      }
    >
      {data && (
        <ChartGridItem minHeight={minHeight}>
          <ReactECharts
            ref={transactionChartRef}
            option={transactionCountsOptions}
            style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
            opts={{ renderer: 'canvas' }}
            notMerge={true}
            lazyUpdate={true}
          />
        </ChartGridItem>
      )}

      {data && (
        <ChartGridItem minHeight={minHeight}>
          <ReactECharts
            ref={tokenChartRef}
            option={uniqueTokenCountsOptions}
            style={{ height: '100%', width: '100%', minHeight: `${minHeight}px` }}
            opts={{ renderer: 'canvas' }}
            notMerge={true}
            lazyUpdate={true}
          />
        </ChartGridItem>
      )}
    </ChartWrapper>
  );
}

import { useMemo, useRef, useState } from 'react';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import { useLocalization } from '@/contexts/LocalizationContext';
import { formatItemTooltip } from '@/util/tooltip-helpers';
import { useChartFiltersSync } from '@/hooks/useChartFiltersSync';
import {
  CHART_COLOR_PALETTE,
  useCarbonChartBaseOption,
} from '@/util/carbon-chart-base';
import type { WinrateRequestParams } from '@/types/chart-api.types';
import { ChartWrapper, ChartContainer, ChartSection, ChartGrid, ChartGridItem } from '../shared';
import type { ChartProps } from '../shared/ChartProp';
import { SegmentedControl, chartControlStyles } from '@/components/charts/shared/ChartControls';
import { useGet, UseGetResp } from '@/hooks/useGet';
import client from '@/api/main';

interface WinrateBin {
  range: string;
  count: number;
  min: number;
  max: number;
}

type WinrateTooltipParam = { value: number; dataIndex: number; name?: string; seriesName?: string };

type WinrateData = {
  wallets: {
    walletAddress: string;
    walletName?: string | undefined;
    winrate: number;
    totalTrades: number;
    winningTrades: number;
    losingTrades: number;
    winningDistribution: WinrateBin[];
    losingDistribution: WinrateBin[];
    avgWinUsd: number;
    avgLossUsd: number;
  }[];
}

export function WinrateChart({
  title,
  minHeight = 400,
  initialFilters = {
    timePeriod: "30D",
    wallets: [],
  },
}: ChartProps) {
  type WinrateTimeRange = "24H" | "7D" | "30D" | "90D";
  const WINRATE_TIME_RANGES: WinrateTimeRange[] = ["24H", "7D", "30D", "90D"];

  const { tr, fmt } = useLocalization();
  const chartTitle = title || tr("charts.winrateChart.title");
  const [timeRange, setTimeRange] = useState<WinrateTimeRange>("30D");

  const overallChartRef = useRef<ReactECharts>(null);
  const baseOption = useCarbonChartBaseOption();

  const { walletsString } = useChartFiltersSync({
    initialFilters,
    debounceDelay: 300,
  });

  useMemo<WinrateRequestParams>(
    () => ({
      period: timeRange,
      wallets: walletsString,
    }),
    [timeRange, walletsString],
  );

  const winRateData: UseGetResp<WinrateData> = useGet(client.api.wallets.analysis.winrate, 200, {
    query: {
      wallets: walletsString ?? "",
      period: timeRange,
    }
  })

  const overallWinrateOption = useMemo((): EChartsOption | null => {
    if (!winRateData.data || winRateData.data.wallets.length == 0) {
      return null;
    }

    const data = winRateData.data;

    const categories = data.wallets.map(w => fmt.text.address(w.walletAddress));
    const winrateValues = data.wallets.map(w => w.winrate);

    return {
      ...baseOption,
      xAxis: {
        ...baseOption.xAxis,
        type: "category",
        data: categories,
        axisLabel: {
          ...baseOption.xAxis.axisLabel,
          interval: 0,
          rotate: categories.length > 5 ? 30 : 0,
        },
      },
      yAxis: {
        ...baseOption.yAxis,
        type: "value",
        name: "Winrate (%)",
        min: 0,
        max: 100,
        axisLabel: {
          ...baseOption.yAxis.axisLabel,
          formatter: "{value}%",
        },
      },
      series: [
        {
          name: "Winrate",
          type: "bar",
          data: winrateValues,
          itemStyle: {
            color: CHART_COLOR_PALETTE[0],
          },
          label: {
            show: true,
            position: 'top',
            formatter: '{c}%',
            color: baseOption.textStyle.color,
          },
        },
      ],
      legend: undefined,
      tooltip: {
        ...baseOption.tooltip,
        trigger: "axis",
        formatter: (params: unknown) => {
          const points = params as WinrateTooltipParam[];
          const param = points[0];
          const wallet = data.wallets[param.dataIndex];
          return formatItemTooltip(fmt.text.address(wallet.walletAddress), [
            { label: "Winrate", value: `${param.value}%` },
            { label: "Winning Trades", value: wallet.winningTrades.toString() },
            { label: "Losing Trades", value: wallet.losingTrades.toString() },
            { label: "Total Trades", value: wallet.totalTrades.toString() },
          ]);
        },
      },
    };
  }, [winRateData.data, baseOption]);

  const distributionCharts = useMemo(() => {
    if (!winRateData.data || winRateData.data.wallets.length == 0) {
      return [];
    }
    const data = winRateData.data;

    return data.wallets.map((wallet) => {
      const categories = [
        ...wallet.losingDistribution.map(d => d.range),
        ...wallet.winningDistribution.map(d => d.range),
      ];
      const winningCounts = [
        ...wallet.losingDistribution.map(() => 0),
        ...wallet.winningDistribution.map(d => d.count),
      ];
      const losingCounts = [
        ...wallet.losingDistribution.map(d => -d.count),
        ...wallet.winningDistribution.map(() => 0),
      ];

      const option: EChartsOption = {
        ...baseOption,
        title: wallet.walletAddress ? {
          text: fmt.text.address(wallet.walletAddress),
          left: 8,
          top: 8,
          textStyle: {
            color: baseOption.textStyle.color,
            fontSize: 16,
            fontWeight: 'bold',
          },
        } : undefined,
        grid: {
          left: "8%",
          right: "8%",
          bottom: "12%",
          top: "24%",
          containLabel: true,
        },
        xAxis: {
          ...baseOption.xAxis,
          type: "category",
          data: categories,
          axisLabel: {
            ...baseOption.xAxis.axisLabel,
            interval: 0,
            rotate: 30,
          },
        },
        yAxis: {
          ...baseOption.yAxis,
          type: "value",
          name: "Trade Count",
          axisLabel: {
            ...baseOption.yAxis.axisLabel,
            formatter: (value: number) => Math.abs(value).toString(),
          },
        },
        series: [
          {
            name: "Winning",
            type: "bar",
            stack: "total",
            data: winningCounts,
            itemStyle: {
              color: CHART_COLOR_PALETTE[1],
            },
          },
          {
            name: "Losing",
            type: "bar",
            stack: "total",
            data: losingCounts,
            itemStyle: {
              color: CHART_COLOR_PALETTE[2],
            },
          },
        ],
        legend: {
          show: true,
          data: ['Winning', 'Losing'],
          textStyle: { color: baseOption.textStyle.color },
        },
        tooltip: {
          ...baseOption.tooltip,
          trigger: "axis",
          axisPointer: {
            type: "shadow",
          },
          formatter: (params: unknown) => {
            const points = params as WinrateTooltipParam[];
            const winning = points.find((p) => p.seriesName === "Winning");
            const losing = points.find((p) => p.seriesName === "Losing");
            return `
              <div style="font-weight: 600; margin-bottom: 8px;">${points[0]?.name ?? ""}</div>
              ${winning ? `<div style="display: flex; justify-content: space-between; gap: 16px;">
                <span style="color: ${CHART_COLOR_PALETTE[1]}">● Winning:</span><strong>${winning.value}</strong>
              </div>` : ''}
              ${losing ? `<div style="display: flex; justify-content: space-between; gap: 16px;">
                <span style="color: ${CHART_COLOR_PALETTE[2]}">● Losing:</span><strong>${Math.abs(losing.value)}</strong>
              </div>` : ''}
            `;
          },
        },
      };

      return {
        walletAddress: wallet.walletAddress,
        option,
      };
    });
  }, [winRateData.data, baseOption]);

  const timeRangeOptions = WINRATE_TIME_RANGES.map(r => ({ value: r, label: r }));

  return (
    <ChartWrapper
      title={chartTitle}
      loadingState={{
        status: winRateData.isLoading ? "loading" : "idle",
        retryCount: 0,
      }}
      isEmpty={winRateData.data ? winRateData.data.wallets.length > 0 : false}
      onRetry={() => winRateData.mutate()}
      toolbarLayout="stacked"
      enableMiniPlayer={false}
      enableExport={false}
      enableFullscreen={false}
      actions={
        <div className={chartControlStyles.toolbar}>
          <SegmentedControl
            ariaLabel={tr("charts.timePeriod")}
            options={timeRangeOptions}
            value={timeRange}
            onChange={(value) => {
              if (
                value === "24H" ||
                value === "7D" ||
                value === "30D" ||
                value === "90D"
              ) {
                setTimeRange(value);
              }
            }}
          />
        </div>
      }
    >
      <ChartContainer gap="0">
        <ChartSection minHeight="300px">
          {overallWinrateOption && (
            <ChartGridItem minHeight={300}>
              <ReactECharts
                ref={overallChartRef}
                option={overallWinrateOption}
                style={{
                  height: "100%",
                  width: "100%",
                  minHeight: `${minHeight}px`,
                }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          )}
        </ChartSection>

        <ChartGrid
          itemCount={distributionCharts?.length}
          autoFit
          minColumnWidth="400px"
        >
          {distributionCharts.map((chart) => (
            <ChartGridItem
              key={chart.walletAddress}
              itemKey={chart.walletAddress}
              minHeight={300}
            >
              <ReactECharts
                option={chart.option}
                style={{ height: "100%", width: "100%" }}
                notMerge
                lazyUpdate
              />
            </ChartGridItem>
          ))}
        </ChartGrid>
      </ChartContainer>
    </ChartWrapper>
  );
}

/**
 * FullscreenView Component
 *
 * Provides fullscreen viewing mode for charts with native API support and modal fallback.
 *
 * Features:
 * - Native Fullscreen API with modal fallback
 * - ESC key handler for exit
 * - Focus trap for keyboard navigation
 * - Dark overlay for enhanced visibility
 * - Loading state during fullscreen transition
 *
 * @module components/charts/shared/FullscreenView
 */

import { Theme } from "@carbon/react";
import React, { useCallback, useEffect, useRef } from "react";
import { createPortal } from "react-dom";
import { useLocalization } from "@/contexts/LocalizationContext";
import { useUserTheme } from "../../../contexts/ThemeContext";
import styles from "./FullscreenView.module.scss";

export interface FullscreenViewProps {
  /** Whether fullscreen mode is active */
  isActive: boolean;

  /** Callback when fullscreen is exited */
  onExit: () => void;

  /** Content to display in fullscreen */
  children: React.ReactNode;

  /** Chart title for accessibility */
  title?: string;
}

/**
 * FullscreenView Component
 *
 * Displays chart content in fullscreen mode with keyboard navigation support.
 * Uses native Fullscreen API when available, falls back to modal overlay.
 */
export const FullscreenView: React.FC<FullscreenViewProps> = ({
  isActive,
  onExit,
  children,
  title = "Chart",
}) => {
  const { tr } = useLocalization();
  const { theme } = useUserTheme();
  const containerRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  /**
   * Handle ESC key press to exit fullscreen
   */
  const handleKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onExit();
      }
    },
    [onExit],
  );

  /**
   * Handle fullscreen change events
   */
  const handleFullscreenChange = useCallback(() => {
    if (!document.fullscreenElement) {
      onExit();
    }
  }, [onExit]);

  /**
   * Request native fullscreen mode
   */
  const requestFullscreen = useCallback(async () => {
    if (!containerRef.current) return;

    try {
      if (containerRef.current.requestFullscreen) {
        await containerRef.current.requestFullscreen();
      }
    } catch (error) {
      console.warn(
        "Fullscreen API not supported, using modal fallback:",
        error,
      );
    }
  }, []);

  /**
   * Exit native fullscreen mode
   */
  const exitFullscreen = useCallback(async () => {
    try {
      if (document.fullscreenElement && document.exitFullscreen) {
        await document.exitFullscreen();
      }
    } catch (error) {
      console.warn("Error exiting fullscreen:", error);
    }
  }, []);

  /**
   * Setup focus trap for keyboard navigation
   */
  useEffect(() => {
    if (!isActive || !containerRef.current) return;

    // Store previously focused element
    previousFocusRef.current = document.activeElement as HTMLElement;

    // Focus the container
    containerRef.current.focus();

    // Setup focus trap
    const focusableElements = containerRef.current.querySelectorAll(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
    );

    const firstElement = focusableElements[0] as HTMLElement;
    const lastElement = focusableElements[
      focusableElements.length - 1
    ] as HTMLElement;

    const handleTabKey = (event: KeyboardEvent) => {
      if (event.key !== "Tab") return;

      if (event.shiftKey) {
        // Shift + Tab
        if (document.activeElement === firstElement) {
          event.preventDefault();
          lastElement?.focus();
        }
      } else {
        // Tab
        if (document.activeElement === lastElement) {
          event.preventDefault();
          firstElement?.focus();
        }
      }
    };

    containerRef.current.addEventListener("keydown", handleTabKey);

    return () => {
      containerRef.current?.removeEventListener("keydown", handleTabKey);

      // Restore focus to previous element
      if (previousFocusRef.current) {
        previousFocusRef.current.focus();
      }
    };
  }, [isActive]);

  /**
   * Setup fullscreen API and keyboard handlers
   */
  useEffect(() => {
    if (!isActive) return;

    // Try to use native fullscreen API
    requestFullscreen();

    // Add event listeners
    document.addEventListener("keydown", handleKeyDown);
    document.addEventListener("fullscreenchange", handleFullscreenChange);

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.removeEventListener("fullscreenchange", handleFullscreenChange);
      exitFullscreen();
    };
  }, [
    isActive,
    handleKeyDown,
    handleFullscreenChange,
    requestFullscreen,
    exitFullscreen,
  ]);

  if (!isActive) {
    return null;
  }

  return createPortal(
    <Theme theme={theme === "dark" ? "g100" : "white"}>
      <div
        ref={containerRef}
        className={styles.fullscreenView}
        role="dialog"
        aria-modal="true"
        aria-label={`${title} - ${tr("charts.fullscreenView")}`}
        tabIndex={-1}
      >
        <div className={styles.header}>
          <h2 className={styles.title}>{title}</h2>
          <button
            className={styles.exitButton}
            onClick={onExit}
            aria-label={tr("charts.exitFullscreen")}
