/**
 * MiniPlayer Component
 *
 * Provides a draggable and resizable mini-player mode for charts.
 *
 * Features:
 * - Drag and resize with react-rnd
 * - ESC key to close
 * - Minimize/maximize controls
 * - Persistent position and size
 * - Z-index management for multiple mini-players
 *
 * @module components/charts/shared/MiniPlayer
 */

import { useUserTheme } from "@/contexts/ThemeContext";
import { Theme } from "@carbon/react";
import React, { useCallback, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { useLocalization } from "@/contexts/LocalizationContext";
import { Rnd } from "react-rnd";
import type { DraggableEventHandler } from "react-draggable";
import styles from "./MiniPlayer.module.scss";

// Constants
const MINI_PLAYER_DEFAULTS = {
  WIDTH: 500,
  HEIGHT: 400,
  MIN_WIDTH: 320,
  MIN_HEIGHT: 240,
  HEADER_HEIGHT: 80,
  MAX_WIDTH_RATIO: 0.9,
  MAX_HEIGHT_RATIO: 0.9,
  Z_INDEX: 999,
} as const;

export interface MiniPlayerProps {
  /** Whether mini-player mode is active */
  isActive: boolean;

  /** Callback when mini-player is closed */
  onClose: () => void;

  /** Content to display in mini-player */
  children: React.ReactNode;

  /** Chart title */
  title?: string;

  /** Initial position (default: bottom-right) */
  defaultPosition?: { x: number; y: number };

  /** Initial size (default: 500x400) */
  defaultSize?: { width: number; height: number };
}

/**
 * MiniPlayer Component
 *
 * Displays chart content in a draggable, resizable mini-player window.
 */
export const MiniPlayer: React.FC<MiniPlayerProps> = ({
  isActive,
  onClose,
  children,
  title = "Chart",
  defaultPosition,
  defaultSize = {
    width: MINI_PLAYER_DEFAULTS.WIDTH,
    height: MINI_PLAYER_DEFAULTS.HEIGHT,
  },
}) => {
  const { tr } = useLocalization();
  const { theme } = useUserTheme();
  const [isMinimized, setIsMinimized] = useState(false);
  const [size, setSize] = useState(defaultSize);
  const previousSizeRef = useRef(defaultSize);

  // Calculate position relative to current scroll position
  const getInitialPosition = useCallback(() => {
    if (defaultPosition) return defaultPosition;

    // Get current scroll position
    const scrollX = window.pageXOffset || document.documentElement.scrollLeft;
    const scrollY = window.pageYOffset || document.documentElement.scrollTop;

    // Calculate position in document coordinates (viewport position + scroll)
    return {
      x: scrollX + window.innerWidth - size.width,
      y: scrollY + window.innerHeight - size.width,
    };
  }, [defaultPosition]);

  const [position, setPosition] = useState(getInitialPosition);

  // Update position when activated to account for current scroll position
  React.useEffect(() => {
    if (isActive) {
      setPosition(getInitialPosition());
    }
  }, [isActive, getInitialPosition]);

  /**
   * Handle ESC key press to close mini-player
   */
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onClose();
      }
    },
    [onClose],
  );

  /**
   * Toggle minimize/maximize state
   */
  const toggleMinimize = useCallback(() => {
    if (isMinimized) {
      // Restore previous size
      setSize(previousSizeRef.current);
    } else {
      // Store current size before minimizing
      previousSizeRef.current = size;
      setSize({
        width: size.width,
        height: MINI_PLAYER_DEFAULTS.HEADER_HEIGHT,
      }); // Minimize to header only
    }
    setIsMinimized(!isMinimized);
  }, [isMinimized, size]);

  /**
   * Handle drag stop to save position
   */
  const handleDragStop: DraggableEventHandler = useCallback(
    (_e, data) => {
      setPosition({
        x: data.x,
        y: Math.max(data.y, MINI_PLAYER_DEFAULTS.HEADER_HEIGHT),
      });
    },
    [],
  );

  /**
   * Handle resize stop to save size
   */
  const handleResizeStop = useCallback(
    (
      _e: MouseEvent | TouchEvent,
      _direction: string,
      ref: HTMLElement,
      _delta: { width: number; height: number },
      position: { x: number; y: number },
    ) => {
      setSize({
        width: ref.offsetWidth,
        height: ref.offsetHeight,
      });
      setPosition({
        x: position.x,
        y: Math.max(position.y, MINI_PLAYER_DEFAULTS.HEADER_HEIGHT),
      });
    },
    [],
  );

  if (!isActive) {
    return null;
  }

  return createPortal(
    <Rnd
      position={{
        x: position.x,
        y: position.y,
      }}
      size={{
        width: size.width,
        height: size.height,
      }}
      minWidth={MINI_PLAYER_DEFAULTS.MIN_WIDTH}
      minHeight={
        isMinimized
          ? MINI_PLAYER_DEFAULTS.HEADER_HEIGHT
          : MINI_PLAYER_DEFAULTS.MIN_HEIGHT
      }
      maxWidth={window.innerWidth * MINI_PLAYER_DEFAULTS.MAX_WIDTH_RATIO}
      maxHeight={window.innerHeight * MINI_PLAYER_DEFAULTS.MAX_HEIGHT_RATIO}
      bounds="parent"
      dragHandleClassName={styles.header}
      onDragStop={handleDragStop}
      onResizeStop={handleResizeStop}
      enableResizing={!isMinimized}
      style={{
        zIndex: MINI_PLAYER_DEFAULTS.Z_INDEX,
      }}
      className={styles.miniPlayer}
    >
      <Theme theme={theme === "dark" ? "g100" : "white"}>
        <div
          className={styles.container}
          onKeyDown={handleKeyDown}
          role="dialog"
          aria-modal="false"
          aria-label={`${title} - ${tr("charts.miniPlayer")}`}
          tabIndex={-1}
        >
          <div className={styles.header}>
            <div className={styles.headerLeft}>
              <div
                className={styles.dragHandle}
                aria-label={tr("charts.dragToMove")}
              >
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 16 16"
                  fill="currentColor"
                >
                  <circle cx="4" cy="4" r="1.5" />
                  <circle cx="4" cy="8" r="1.5" />
                  <circle cx="4" cy="12" r="1.5" />
                  <circle cx="8" cy="4" r="1.5" />
                  <circle cx="8" cy="8" r="1.5" />
                  <circle cx="8" cy="12" r="1.5" />
                </svg>
              </div>
              <h3 className={styles.title}>{title}</h3>
            </div>

            <div className={styles.headerRight}>
              <button
                className={styles.minimizeButton}
                onClick={toggleMinimize}
                aria-label={
                  isMinimized ? tr("charts.maximize") : tr("charts.minimize")
                }
                title={
                  isMinimized ? tr("charts.maximize") : tr("charts.minimize")
                }
              >
                {isMinimized ? (
                  <svg
                    width="16"
                    height="16"
                    viewBox="0 0 16 16"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                  >
                    <polyline points="4 9 8 5 12 9" />
                  </svg>
                ) : (
                  <svg
                    width="16"
                    height="16"
                    viewBox="0 0 16 16"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2"
                  >
                    <line x1="2" y1="8" x2="14" y2="8" />
                  </svg>
                )}
              </button>

              <button
                className={styles.closeButton}
                onClick={onClose}
                aria-label={tr("charts.closeMiniPlayer")}
                title={tr("charts.closeMiniPlayerEsc")}
              >
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 16 16"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <line x1="12" y1="4" x2="4" y2="12" />
                  <line x1="4" y1="4" x2="12" y2="12" />
                </svg>
              </button>
            </div>
          </div>

          {!isMinimized && <div className={styles.content}>{children}</div>}
        </div>
      </Theme>
    </Rnd>,
    document.body,
  );
};

export default MiniPlayer;

import {
  createContext,
  useCallback,
  useContext,
  useState,
  type ReactNode,
} from "react";
import { ToastContainer, type ToastItem } from "./ToastContainer";
import type { ToastKind } from "./Toast";

interface ToastOptions {
  subtitle?: string;
  action?: { label: string; onClick: () => void };
}

interface ToastContextValue {
  toast: (kind: ToastKind, title: string, opts?: ToastOptions) => void;
}

const ToastContext = createContext<ToastContextValue | null>(null);

let nextId = 1;

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<ToastItem[]>([]);

  const addToast = useCallback(
    (kind: ToastKind, title: string, opts?: ToastOptions) => {
      const id = nextId++;
      setToasts((prev) => [...prev, { id, kind, title, ...opts }]);
      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, 6000);
    },
    [],
  );

  const removeToast = useCallback((id: number) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ toast: addToast }}>
      {children}
      <ToastContainer toasts={toasts} onClose={removeToast} />
    </ToastContext.Provider>
  );
}

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) {
    throw new Error("useToast must be used within a ToastProvider");
  }
  return ctx;
}

import { useMemo } from "react";
import classNames from "classnames";
import { useNavigate } from "react-router";
import { InlineLoading } from "@carbon/react";
import styles from "./DexTable.module.scss";
import { TknImg } from "@/components/TknImg";
import { useLocalization } from "@/contexts/LocalizationContext";
import {
  CaretUp,
  CaretDown,
  ArrowUp,
  ArrowDown,
} from "@carbon/icons-react";

export interface DexTableItem {
  id: string;
  poolAddress: string;
  baseAddress: string;
  baseSymbol: string;
  baseName?: string;
  quoteSymbol: string;
  poolName: string;
  dexName: string;
  baseImageUrl: string | null;
  quoteImageUrl?: string | null;
  marketCapUsd: number | null;
  fdvUsd: number | null;
  priceUsd: number | null;
  txns24h: number | null;
  volume24h: number | null;
  priceChange5m: number | null;
  priceChange1h: number | null;
  priceChange6h: number | null;
  priceChange24h: number | null;
  liquidityUsd: number | null;
  poolCreatedAt: string | null;
}

interface DexTableProps {
  data?: DexTableItem[];
  loading?: boolean;
  sortKey?: SortKey | "none";
  sortDirection?: "asc" | "desc";
  filters?: TableFilters;
  onSort?: (key: SortKey) => void;
}

export type SortKey =
  | "marketCap"
  | "price"
  | "age"
  | "txns"
  | "volume"
  | "5m"
  | "1h"
  | "6h"
  | "24h"
  | "liquidity";

export interface RangeFilter {
  min?: string;
  max?: string;
}

export interface TableFilters {
  liquidity: RangeFilter;
  mcap: RangeFilter;
  volume: RangeFilter;
  txns: RangeFilter;
  age: RangeFilter;
  change24h: RangeFilter;
}

export const INITIAL_FILTERS: TableFilters = {
  liquidity: {},
  mcap: {},
  volume: {},
  txns: {},
  age: {},
  change24h: {},
};

function formatAge(dateStr: string | null, justNowLabel: string): string {
  if (!dateStr) return "-";
  const ms = Date.now() - new Date(dateStr).getTime();
  if (ms < 0) return "-";

  const days = Math.floor(ms / 86400000);
  if (days > 0) return `${days}d`;

  const hours = Math.floor(ms / 3600000);
  if (hours > 0) return `${hours}h`;

  const mins = Math.floor(ms / 60000);
  if (mins > 0) return `${mins}m`;

  return justNowLabel;
}

function getSortValue(item: DexTableItem, key: SortKey): number {
  switch (key) {
    case "marketCap":
      return item.marketCapUsd || item.fdvUsd || 0;
    case "price":
      return item.priceUsd || 0;
    case "age":
      return item.poolCreatedAt ? new Date(item.poolCreatedAt).getTime() : 0;
    case "txns":
      return item.txns24h || 0;
    case "volume":
      return item.volume24h || 0;
    case "5m":
      return item.priceChange5m || -999999;
    case "1h":
      return item.priceChange1h || -999999;
    case "6h":
      return item.priceChange6h || -999999;
    case "24h":
      return item.priceChange24h || -999999;
    case "liquidity":
      return item.liquidityUsd || 0;
    default:
      return 0;
  }
}

export function DexTable({
  data = [],
  loading = false,
  sortKey = "5m",
  sortDirection = "desc",
  filters = INITIAL_FILTERS,
  onSort,
}: DexTableProps) {
  const { tr, fmt } = useLocalization();
  const navigate = useNavigate();

  const sortedData = useMemo(() => {
    if (!data.length) return [];

    let filtered = [...data];

    // Apply Filters
    filtered = filtered.filter((item) => {
      const checkRange = (val: number | null, range: RangeFilter) => {
        if (val === null) return true;
        const min = range.min ? parseFloat(range.min) : -Infinity;
        const max = range.max ? parseFloat(range.max) : Infinity;
        return val >= min && val <= max;
      };

      const ageHours = item.poolCreatedAt
        ? (Date.now() - new Date(item.poolCreatedAt).getTime()) / 3600000
        : null;

      return (
        checkRange(item.liquidityUsd, filters.liquidity) &&
        checkRange(item.marketCapUsd || item.fdvUsd, filters.mcap) &&
        checkRange(item.volume24h, filters.volume) &&
        checkRange(item.txns24h, filters.txns) &&
        checkRange(ageHours, filters.age) &&
        checkRange(item.priceChange24h, filters.change24h)
      );
    });

    // Apply Sorting
    return filtered.sort((a, b) => {
      const valA = getSortValue(a, sortKey as SortKey);
      const valB = getSortValue(b, sortKey as SortKey);

      if (valA === valB) return 0;

      const comparison = valA > valB ? 1 : -1;
      return sortDirection === "desc" ? -comparison : comparison;
    });
  }, [data, sortKey, sortDirection, filters]);

  const formatCompactPercentText = (val: number) => {
    const absVal = Math.abs(val);
    if (absVal < 100) {
      return `${Number(absVal.toFixed(2))}%`;
    } else if (absVal < 100000) {
      const truncated = Math.trunc(absVal);
      return `${Intl.NumberFormat("en-US").format(truncated)}%`;
    } else {
      const compact = Intl.NumberFormat("en-US", {
        notation: "compact",
        maximumFractionDigits: 1,
      }).format(absVal);
      return `${compact}%`;
    }
  };

  const renderTrend = (val: number | null) => {
    if (val == null) return "-";
    const clz =
      val > 0 ? styles.positive : val < 0 ? styles.negative : styles.neutral;
    const sign = val > 0 ? "+" : val < 0 ? "-" : "";
    return (
      <span className={classNames(styles.trendValue, clz)}>
        {sign}
        {formatCompactPercentText(val)}
      </span>
    );
  };

  if (loading) {
    return (
      <div className={styles.loadingState}>
        <div className={styles.loadingIndicator}>
          <InlineLoading
            status="active"
            description={tr("marketPage.loadingMarketData")}
          />
        </div>
      </div>
    );
  }

  if (data.length === 0) {
    return (
      <div className={styles.dexTableContainer}>
        <div className={styles.emptyState}>{tr("marketPage.noPoolsFound")}</div>
      </div>
    );
  }

  return (
    <div className={styles.dexTableContainer}>
      <table className={styles.dexTable}>
        <thead>
          <tr>
            <th className={styles.alignLeft}>{tr("marketPage.token")}</th>
            <th onClick={() => onSort && onSort("marketCap")}>
              {tr("marketPage.mcap")}
              {sortKey === "marketCap" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("price")}>
              {tr("marketPage.price")}
              {sortKey === "price" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("age")}>
              {tr("marketPage.age")}
              {sortKey === "age" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("txns")}>
              {tr("marketPage.txns")}
              {sortKey === "txns" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("volume")}>
              {tr("marketPage.volume")}
              {sortKey === "volume" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("5m")}>
              5M
              {sortKey === "5m" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("1h")}>
              1H
              {sortKey === "1h" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("6h")}>
              6H
              {sortKey === "6h" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("24h")}>
              24H
              {sortKey === "24h" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <CaretUp size={14} />
                  ) : (
                    <CaretDown size={14} />
                  )}
                </span>
              )}
            </th>
            <th onClick={() => onSort && onSort("liquidity")}>
              {tr("marketPage.liquidity")}
              {sortKey === "liquidity" && (
                <span
                  className={classNames(styles.sortIndicator, styles.active)}
                >
                  {sortDirection === "asc" ? (
                    <ArrowUp size={14} />
                  ) : (
                    <ArrowDown size={14} />
                  )}
                </span>
              )}
            </th>
          </tr>
        </thead>
        <tbody>
          {sortedData.map((pool, idx) => {
            const mcap = pool.marketCapUsd || pool.fdvUsd;

            const baseSymbol = pool.baseSymbol?.toUpperCase() || "UNK";
            const quoteSymbol = pool.quoteSymbol?.toUpperCase() || "UNK";
            const baseDescription =
              pool.baseName && pool.baseName.toUpperCase() !== baseSymbol
                ? pool.baseName
                : null;

            return (
              <tr key={pool.poolAddress}>
                <td className={styles.alignLeft}>
                  <div
                    className={styles.tokenCell}
                    onClick={() =>
                      navigate(
                        `/tokens/${pool.baseAddress}/${pool.poolAddress}`,
                      )
                    }
                    style={{ cursor: "pointer" }}
                  >
                    <span className={styles.rank}>#{idx + 1}</span>
                    <div className={styles.doubleImage}>
                      <div className={styles.baseImgWrapper}>
                        <TknImg
                          src={pool.baseImageUrl}
                          alt={baseDescription || baseSymbol}
                          size={28}
                        />
                      </div>
                      <div className={styles.quoteImgWrapper}>
                        <TknImg
                          src={pool.quoteImageUrl || null}
                          alt={pool.quoteSymbol}
                          size={14}
                        />
                      </div>
                    </div>
                    <div className={styles.pairNamesText}>
                      <span className={styles.baseSy}>{baseSymbol}</span>
                      <span className={styles.quoteSy}>/{quoteSymbol}</span>
                      {baseDescription && (
                        <span
                          className={styles.poolDescription}
                          title={baseDescription}
                        >
                          {baseDescription}
                        </span>
                      )}
                    </div>
                  </div>
                </td>
                <td>
                  <span className={styles.numberValue}>
                    {mcap ? fmt.num.compact.currency(mcap) : "-"}
                  </span>
                </td>
                <td>
                  <span className={styles.numberValue}>
                    {pool.priceUsd ? fmt.num.currency(pool.priceUsd) : "-"}
                  </span>
                </td>
                <td>
                  <span className={styles.secondaryValue}>
                    {formatAge(pool.poolCreatedAt, tr("marketPage.justNow"))}
                  </span>
                </td>
                <td>
                  <span className={styles.numberValue}>
                    {pool.txns24h ? fmt.num.compact.decimal(pool.txns24h) : "-"}
                  </span>
                </td>
                <td>
                  <span className={styles.numberValue}>
                    {pool.volume24h
                      ? fmt.num.compact.currency(pool.volume24h)
                      : "-"}
                  </span>
                </td>
                <td className={styles.numberValue}>
                  {renderTrend(pool.priceChange5m)}
                </td>
                <td className={styles.numberValue}>
                  {renderTrend(pool.priceChange1h)}
                </td>
                <td className={styles.numberValue}>
                  {renderTrend(pool.priceChange6h)}
                </td>
                <td className={styles.numberValue}>
                  {renderTrend(pool.priceChange24h)}
                </td>
                <td>
                  <span className={styles.numberValue}>
                    {pool.liquidityUsd
                      ? fmt.num.compact.currency(pool.liquidityUsd)
                      : "-"}
                  </span>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

