const getHeaders = (tr: ReturnType<typeof useLocalization>["tr"]) => [
  { key: "token", header: tr("marketPage.token") },
  { key: "price", header: tr("marketPage.price") },
  { key: "change24h", header: tr("marketPage.change24h") },
  { key: "volume24h", header: tr("marketPage.volume24h") },
  { key: "marketCap", header: tr("marketPage.marketCap") },
  { key: "supply", header: tr("token.marketStats.circSupply") },
];

export const TokenPerformanceTable: React.FC<TokenPerformanceTableProps> = ({
  onTokenSelect,
  selectedTokenAddress,
}) => {
  const { tr, fmt } = useLocalization();
  const [tokens, setTokens] = useState<TokenPerformance[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const headers = getHeaders(tr);

  // Handle row click
  const handleRowClick = (tokenId: string) => {
    const token = tokens.find((t) => t.id === tokenId);
    if (token && onTokenSelect) {
      onTokenSelect(token);
    }
  };

  useEffect(() => {
    async function fetchTokenData() {
      try {
        setLoading(true);
        setError(null);

        const apiDomain =
          import.meta.env.VITE_CLIENT_API_DOMAIN || window.location.origin;

        // Batch tokens into smaller chunks to avoid API issues
        const BATCH_SIZE = 10;
        const batches: string[][] = [];
        for (let i = 0; i < SOLANA_TOKEN_ADDRESSES.length; i += BATCH_SIZE) {
          batches.push(SOLANA_TOKEN_ADDRESSES.slice(i, i + BATCH_SIZE));
        }

        const allMarketData: TokenMarketDataItem[] = [];
        const allMetaData: TokenMetaDataItem[] = [];

        // Fetch each batch separately with error handling per batch
        for (const batch of batches) {
          const addressesParam = batch.join(",");

          try {
            // Fetch market data and meta data in parallel for this batch
            const [marketResp, metaResp] = await Promise.all([
              fetch(`${apiDomain}/api/tokens/markets/${addressesParam}`),
              fetch(`${apiDomain}/api/tokens/meta/${addressesParam}`),
            ]);

            // Process market data if successful
            if (marketResp.ok) {
              const marketData = (await marketResp.json()) as MarketData;
              if (Array.isArray(marketData)) {
                allMarketData.push(...marketData);
              }
            } else {
              console.warn(
                `Failed to fetch market data for batch: ${batch.join(",").substring(0, 50)}...`,
              );
            }

            // Process meta data if successful
            if (metaResp.ok) {
              const metaData = (await metaResp.json()) as MetaData;
              if (Array.isArray(metaData)) {
                allMetaData.push(...metaData);
              }
            } else {
              console.warn(
                `Failed to fetch meta data for batch: ${batch.join(",").substring(0, 50)}...`,
              );
            }
          } catch (batchError) {
            // Log but continue with other batches
            console.warn(
              `Error fetching batch: ${batch.join(",").substring(0, 50)}...`,
              batchError,
            );
          }
        }

        // If no market data was fetched at all, show error
        if (allMarketData.length === 0) {
          setError(tr("ERROR.FAILED_TO_FETCH_REQUESTED_DATA"));
          setLoading(false);
          return;
        }

        // Create a lookup map for meta data by address
        const metaLookup = new Map(allMetaData.map((m) => [m.address, m]));

        // Combine market and meta data, filtering out invalid entries
        const combinedTokens: TokenPerformance[] = allMarketData
          .filter(
            (market) => market && market.address && market.priceUsd != null,
          )
          .map((market, index) => {
            const meta = metaLookup.get(market.address);
            return {
              id: String(index + 1),
              address: market.address,
              token: meta?.name || "Unknown",
              symbol: meta?.symbol?.toUpperCase() || "???",
              imageUrl: meta?.imageUrl || null,
              price: Number(market.priceUsd) || 0,
              change24h: Number(market.priceChangePercentage24h || 0),
              volume24h: Number(market.volume24h) || 0,
              marketCap: Number(market.marketCap) || 0,
              supply: Number(market.circulatingSupply) || 0,
              totalSupply: Number(market.totalSupply) || 0,
              ath: Number(market.ath) || 0,
              athChangePercentage: Number(market.athChangePercentage) || 0,
              atl: Number(market.atl) || 0,
              atlChangePercentage: Number(market.atlChangePercentage) || 0,
            };
          })
          // Sort by market cap descending
          .sort((a, b) => b.marketCap - a.marketCap);

        setTokens(combinedTokens);

        // Show partial success message if some tokens were skipped
        if (combinedTokens.length < SOLANA_TOKEN_ADDRESSES.length) {
          console.info(
            `Loaded ${combinedTokens.length} of ${SOLANA_TOKEN_ADDRESSES.length} tokens`,
          );
        }
      } catch (err) {
        console.error("Failed to fetch token data:", err);
        setError(tr("ERROR.FAILED_TO_FETCH_REQUESTED_DATA"));
      } finally {
        setLoading(false);
      }
    }

    fetchTokenData();
  }, []);

  // Removed local formatNumber

  const formatSupply = (num: number, symbol: string) => {
    if (num >= 1e12) return `${(num / 1e12).toFixed(2)}T ${symbol}`;
    if (num >= 1e9) return `${(num / 1e9).toFixed(2)}B ${symbol}`;
    if (num >= 1e6) return `${(num / 1e6).toFixed(2)}M ${symbol}`;
    return `${fmt.num.decimal(num)} ${symbol}`;
  };

  const rows = tokens.map((token) => ({
    id: token.id,
    token: (
      <div className={styles.tokenCell}>
        {token.imageUrl && (
          <img
            src={token.imageUrl}
            alt={token.token}
            className={styles.tokenImage}
            width={24}
            height={24}
          />
        )}
        <div className={styles.tokenInfo}>
          <span className={styles.tokenName}>{token.token}</span>
          <span className={styles.tokenSymbol}>{token.symbol}</span>
        </div>
      </div>
    ),
    price: fmt.num.currency(token.price),
    change24h: (
      <span
        className={token.change24h >= 0 ? styles.positive : styles.negative}
      >
        {token.change24h >= 0 ? <ArrowUp size={16} /> : <ArrowDown size={16} />}
        {Math.abs(token.change24h).toFixed(2)}%
      </span>
    ),
    volume24h: fmt.num.compact.currency(token.volume24h),
    marketCap: fmt.num.compact.currency(token.marketCap),
    supply: formatSupply(token.supply, token.symbol),
  }));
  /**
   * Handle export functionality
   */
  const handleExport = async (format: ExportFormat) => {
    if (format === "csv") {
      // Export as CSV
      const csvHeaders = headers.map((h) => h.header).join(",");
      const csvRows = tokens.map((token) =>
        [
          token.token,
          token.symbol,
          token.price.toFixed(6),
          token.change24h.toFixed(2),
          token.volume24h.toString(),
          token.marketCap.toString(),
          token.supply.toString(),
        ].join(","),
      );
      const csvContent = [csvHeaders, ...csvRows].join("\n");

      const blob = new Blob([csvContent], { type: "text/csv" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `token-performance-${Date.now()}.csv`;
      link.click();
      URL.revokeObjectURL(url);
    }
  };
  if (loading) {
    return (
      <TableWrapper
        title={tr("marketPage.tokenPerformanceTitle")}
        onExport={handleExport}
        isEmpty={true}
      >
        <div className={styles.loadingState}>{tr("common.loading")}</div>
      </TableWrapper>
    );
  }

  if (error) {
    return (
      <TableWrapper
        title={tr("marketPage.tokenPerformanceTitle")}
        onExport={handleExport}
        isEmpty={true}
      >
        <div className={styles.errorState}>{error}</div>
      </TableWrapper>
    );
  }

  return (
    <TableWrapper
      title={tr("marketPage.tokenPerformanceTitle")}
      onExport={handleExport}
      isEmpty={tokens.length === 0}
    >
      <div className={styles.tokenPerformanceTable}>
        <DataTable rows={rows} headers={headers}>
          {({ rows, headers, getTableProps, getHeaderProps, getRowProps }) => (
            <Table {...getTableProps()}>
              <TableHead>
                <TableRow>
                  {headers.map((header) => {
                    const { key, ...headerProps } = getHeaderProps({ header });
                    return (
                      <TableHeader key={key} {...headerProps}>
                        {header.header}
                      </TableHeader>
                    );
                  })}
                </TableRow>
              </TableHead>
              <TableBody>
                {rows.map((row) => {
                  const { key, ...rowProps } = getRowProps({ row });
                  const token = tokens.find((t) => t.id === row.id);
                  const isSelected = token?.address === selectedTokenAddress;
                  return (
                    <TableRow
                      key={key}
                      {...rowProps}
                      className={`${styles.clickableRow} ${isSelected ? styles.selectedRow : ""}`}
                      onClick={() => handleRowClick(row.id)}
                    >
                      {row.cells.map((cell) => (
                        <TableCell key={cell.id}>{cell.value}</TableCell>
                      ))}
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          )}
        </DataTable>
      </div>
    </TableWrapper>
  );
};

/**
 * TokenPriceHistoryChart Component
 *
 * Displays price history chart for a single token using real API data.
 * Features time period selection similar to CoinGecko.
 */

import React, { useEffect, useState, useMemo, useRef } from 'react';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import { Tile, SkeletonPlaceholder, Button } from '@carbon/react';
import { Maximize, Save, Download } from '@carbon/icons-react';
import styles from './TokenPriceHistoryChart.module.scss';

interface ChartDataPoint {
  address: string | null;
  unixTimestampMs: number;
  price: number;
  marketCap: number;
  totalVolume: number;
}

type TimePeriod = '30m' | '1h' | '24h' | '7d' | '30d';

interface TokenPriceHistoryChartProps {
  /** Token address to fetch data for */
  tokenAddress?: string | null;
  /** Token symbol for display */
  tokenSymbol?: string;
  /** Chart height in pixels */
  height?: number;
}

const TIME_PERIODS: { value: TimePeriod; label: string }[] = [
  { value: '30m', label: '30 min' },
  { value: '1h', label: '1h' },
  { value: '24h', label: '24h' },
  { value: '7d', label: '7 days' },
  { value: '30d', label: '30 days' },
];

export const TokenPriceHistoryChart: React.FC<TokenPriceHistoryChartProps> = ({
  tokenAddress,
  tokenSymbol = 'Token',
  height = 400,
}) => {
  const [chartData, setChartData] = useState<ChartDataPoint[]>([]);
  const [selectedPeriod, setSelectedPeriod] = useState<TimePeriod>('24h');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const chartRef = useRef<ReactECharts>(null);

  // Fetch chart data when token or period changes
  useEffect(() => {
    if (!tokenAddress) {
      setChartData([]);
      return;
    }

    const fetchChartData = async () => {
      setLoading(true);
      setError(null);

      try {
        const apiDomain = import.meta.env.VITE_CLIENT_API_DOMAIN || window.location.origin;
        const response = await fetch(
          `${apiDomain}/api/tokens/markets/chart/${tokenAddress}?period=${selectedPeriod}`
        );

        if (!response.ok) {
          throw new Error('Failed to fetch chart data');
        }

        const data = await response.json();
        setChartData(data);
      } catch (err) {
        console.error('Failed to fetch chart data:', err);
        setError('Failed to load price history');
      } finally {
        setLoading(false);
      }
    };

    fetchChartData();
  }, [tokenAddress, selectedPeriod]);

  // Handle period change
  const handlePeriodChange = (period: TimePeriod) => {
    setSelectedPeriod(period);
  };

  // Format currency for display
  const formatCurrency = (value: number) => {
    if (value < 0.01) return `$${value.toFixed(6)}`;
    if (value < 1) return `$${value.toFixed(4)}`;
    if (value >= 1e9) return `$${(value / 1e9).toFixed(2)}B`;
    if (value >= 1e6) return `$${(value / 1e6).toFixed(2)}M`;
    if (value >= 1e3) return `$${(value / 1e3).toFixed(2)}K`;
    return `$${value.toFixed(2)}`;
  };

  // Generate ECharts options
  const chartOptions: EChartsOption = useMemo(() => {
    if (chartData.length === 0) {
      return {};
    }

    const sortedData = [...chartData].sort((a, b) => a.unixTimestampMs - b.unixTimestampMs);
    const prices = sortedData.map(d => d.price);
    const minPrice = Math.min(...prices);
    const maxPrice = Math.max(...prices);
    const priceRange = maxPrice - minPrice;

    return {
      grid: {
        left: 60,
        right: 20,
        top: 20,
        bottom: 60,
        containLabel: false,
      },
      tooltip: {
        trigger: 'axis',
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        borderColor: 'transparent',
        textStyle: {
          color: '#fff',
        },
        formatter: (params: any) => {
          if (!Array.isArray(params) || params.length === 0) return '';
          const point = params[0];
          const date = new Date(point.data[0]);
          const dateStr = selectedPeriod === '30m' || selectedPeriod === '1h'
            ? date.toLocaleTimeString()
            : date.toLocaleDateString() + ' ' + date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
          return `
            <div style="padding: 8px;">
              <div style="margin-bottom: 4px; font-weight: bold;">${tokenSymbol}</div>
              <div style="color: #888; margin-bottom: 4px;">${dateStr}</div>
              <div style="font-size: 16px; font-weight: bold;">${formatCurrency(point.data[1])}</div>
            </div>
          `;
        },
      },
      xAxis: {
        type: 'time',
        axisLine: {
          lineStyle: {
            color: '#444',
          },
        },
        axisLabel: {
          color: '#888',
          formatter: (value: number) => {
            const date = new Date(value);
            if (selectedPeriod === '30m' || selectedPeriod === '1h') {
              return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
            }
            if (selectedPeriod === '24h') {
              return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
            }
            return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
          },
        },
        splitLine: {
          show: false,
        },
      },
      yAxis: {
        type: 'value',
        min: minPrice - priceRange * 0.1,
        max: maxPrice + priceRange * 0.1,
        axisLine: {
          show: false,
        },
        axisLabel: {
          color: '#888',
          formatter: (value: number) => formatCurrency(value),
        },
        splitLine: {
          lineStyle: {
            color: '#333',
            type: 'dashed',
          },
        },
      },
      series: [
        {
          name: tokenSymbol,
          type: 'line',
          data: sortedData.map(d => [d.unixTimestampMs, d.price]),
          smooth: true,
          symbol: 'none',
          lineStyle: {
            width: 2,
            color: '#4589ff',
          },
          areaStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                { offset: 0, color: 'rgba(69, 137, 255, 0.3)' },
                { offset: 1, color: 'rgba(69, 137, 255, 0.05)' },
              ],
            },
          },
        },
      ],
      dataZoom: [
        {
          type: 'inside',
          xAxisIndex: 0,
          start: 0,
          end: 100,
        },
      ],
    };
  }, [chartData, tokenSymbol, selectedPeriod]);

  // Handle export as PNG
  const handleExport = () => {
    const echartsInstance = chartRef.current?.getEchartsInstance();
    if (echartsInstance) {
      const url = echartsInstance.getDataURL({
        type: 'png',
        pixelRatio: 2,
        backgroundColor: '#1a1a1a',
      });
      const link = document.createElement('a');
      link.href = url;
      link.download = `${tokenSymbol}-price-history-${selectedPeriod}.png`;
      link.click();
    }
  };

  // Empty state
  if (!tokenAddress) {
    return (
      <Tile className={styles.chartContainer}>
        <div className={styles.header}>
          <h3 className={styles.title}>Price History</h3>
        </div>
        <div className={styles.emptyState} style={{ height }}>
          <p>Select a token to view price history</p>
        </div>
      </Tile>
    );
  }

  // Loading state
  if (loading && chartData.length === 0) {
    return (
      <Tile className={styles.chartContainer}>
        <div className={styles.header}>
          <h3 className={styles.title}>Price History</h3>
        </div>
        <SkeletonPlaceholder style={{ height, width: '100%' }} />
      </Tile>
    );
  }

  return (
    <Tile className={styles.chartContainer}>
      <div className={styles.header}>
        <h3 className={styles.title}>Price History</h3>
        <div className={styles.actions}>
          <Button
            kind="ghost"
            size="sm"
            hasIconOnly
            iconDescription="Fullscreen"
            renderIcon={Maximize}
          />
          <Button
            kind="ghost"
            size="sm"
            hasIconOnly
            iconDescription="Save"
            renderIcon={Save}
          />
          <Button
            kind="ghost"
            size="sm"
            hasIconOnly
            iconDescription="Export"
            renderIcon={Download}
            onClick={handleExport}
          />
        </div>
      </div>

      <div className={styles.timePeriodSelector}>
        {TIME_PERIODS.map(period => (
          <button
            key={period.value}
            type="button"
            className={`${styles.periodButton} ${selectedPeriod === period.value ? styles.active : ''}`}
            onClick={() => handlePeriodChange(period.value)}
          >
            {period.label}
          </button>
        ))}
      </div>

      {error ? (
        <div className={styles.errorState} style={{ height }}>
          <p>{error}</p>
        </div>
      ) : chartData.length === 0 ? (
        <div className={styles.emptyState} style={{ height }}>
          <p>No price data available for this period</p>
        </div>
      ) : (
        <ReactECharts
          ref={chartRef}
          option={chartOptions}
          style={{ height, width: '100%' }}
          opts={{ renderer: 'canvas' }}
          notMerge={true}
        />
      )}
    </Tile>
  );
};

import { loadStripe } from "@stripe/stripe-js";
import { Elements } from "@stripe/react-stripe-js";
import { useEffect, useState } from "react";
import { AlertCircle, X } from "lucide-react";
import { CheckoutForm } from "./CheckoutForm";
import { useLocalization } from "@/contexts/LocalizationContext";

type Tier = {
  name: string;
  price: string;
};

type PaymentMethod = "card" | "bank" | "solana";

type PaymentModalWrapperProps = {
  open: boolean;
  tier: Tier | null;
  onClose: () => void;
  onSuccess: () => void;
};

type IntentState =
  | { status: "idle" }
  | { status: "ready"; tier: string; stripePromise: ReturnType<typeof loadStripe> }
  | { status: "error"; message: string };

/**
 * Wraps the Stripe Elements provider using Deferred Intent Creation.
 * 
 * Instead of creating the SetupIntent upfront:
 *   1. Load Stripe immediately
 *   2. Create Elements without clientSecret (deferred mode)
 *   3. User selects a payment method card
 *   4. On "Subscribe Now", CheckoutForm creates the SetupIntent with the selected paymentMethodTypes
 *   5. CheckoutForm then confirms with confirmSetup()
 *   6. On success → CheckoutForm calls POST /api/payment/activate-subscription
 */
export function PaymentModalWrapper({
  open,
  tier,
  onClose,
  onSuccess,
}: PaymentModalWrapperProps) {
  const { tr } = useLocalization();
  const [intentState, setIntentState] = useState<IntentState>({ status: "idle" });
  const [activeMethod, setActiveMethod] = useState<PaymentMethod>("card");

  useEffect(() => {
    if (!open || !tier) {
      setIntentState({ status: "idle" });
      return;
    }

    setActiveMethod("card");

    const paidTiers = ["Lite", "Plus", "Pro"];
    if (!paidTiers.includes(tier.name)) return;

    try {
      // Load Stripe immediately (no need to wait for SetupIntent)
      const stripePromise = loadStripe(
        import.meta.env.VITE_STRIPE_PUBLISHABLE_KEY as string || "",
      );

      setIntentState({
        status: "ready",
        tier: tier.name,
        stripePromise,
      });

      console.log("[PaymentModalWrapper] Stripe loaded for deferred intent creation");
    } catch (err) {
      console.error("[PaymentModalWrapper]", err);
      setIntentState({
        status: "error",
        message: tr("payment.errors.loadStripe"),
      });
    }
  }, [open, tier]);

  if (!open || !tier) return null;

  return (
    <>
      <div
        className="fixed inset-0 z-[200] bg-[#050509]/80 backdrop-blur-md"
        onClick={onClose}
        aria-hidden="true"
      />

      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="payment-modal-title"
        className="fixed inset-0 z-[201] flex items-center justify-center p-4 pointer-events-none"
      >
        <div className="pointer-events-auto flex max-h-[90vh] w-full max-w-xl flex-col overflow-hidden !rounded-3xl border border-white/10 bg-[#0f0f17]/95 shadow-[0_28px_100px_-44px_rgba(124,58,237,0.55)] backdrop-blur-xl">
          {/* Header */}
          <div className="border-b border-white/10 !px-6 !py-6 sm:!px-8 sm:!py-7">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-[10px] font-bold uppercase tracking-[0.2em] text-[#64748b] mb-1">
                  {tr("payment.modal.eyebrow")}
                </p>
                <h2
                  id="payment-modal-title"
                  className="text-white font-bold text-xl tracking-tight"
                >
                  {tr("payment.modal.title", { tierName: tier.name })}
                </h2>
              </div>
              <button
                id="payment-modal-close-btn"
                type="button"
                onClick={onClose}
                className="!rounded-full border border-transparent p-2 text-[#64748b] transition-colors hover:border-white/10 hover:bg-white/5 hover:text-white"
                aria-label={tr("payment.modal.close")}
              >
                <X className="h-5 w-5" aria-hidden="true" />
              </button>
            </div>
          </div>

          {/* Body */}
          <div className="custom-scrollbar overflow-y-auto !px-6 !py-6 sm:!px-8 sm:!py-7">
            {intentState.status === "error" && (
              <div className="flex flex-col items-center gap-4 py-8 text-center">
                <div className="flex h-12 w-12 items-center justify-center !rounded-3xl border border-red-500/20 bg-red-500/10">
                  <AlertCircle className="h-6 w-6 text-red-400" aria-hidden="true" />
                </div>
                <p className="text-red-400 text-sm">{intentState.message}</p>
                <button
                  type="button"
                  onClick={onClose}
                  className="text-sm text-[#78a9ff] hover:underline"
                >
                  {tr("payment.shared.close")}
                </button>
              </div>
            )}

            {intentState.status === "ready" && (
              <Elements
                key={`elements-${activeMethod === "bank" ? "bank" : "card"}`}
                stripe={intentState.stripePromise}
                options={{
                  mode: "setup",
                  currency: "usd",
                  locale: "en",
                  paymentMethodTypes:
                    activeMethod === "bank" ? ["us_bank_account"] : ["card"],
                  appearance: {
                    theme: "night",
                    variables: {
                      colorPrimary: "#7C3AED",
                      colorBackground: "#0f0f17",
                      colorText: "#f8fafc",
                      colorDanger: "#f87171",
                      fontFamily: "Inter, sans-serif",
                      borderRadius: "12px",
                      spacingUnit: "5px",
                    },
                  },
                }}
              >
                <CheckoutForm
                  tierName={tier.name}
                  tierPrice={tier.price}
                  tierKey={intentState.tier as "Lite" | "Plus" | "Pro"}
                  activeMethod={activeMethod}
                  onMethodChange={setActiveMethod}
                  onSuccess={onSuccess}
                  onCancel={onClose}
                />
              </Elements>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

import { Button } from "@carbon/react";
import ProfileLoadingState from "@/components/profile/shared/ProfileLoadingState";
import { Activity, ChartColumn, Currency, Wallet } from "@carbon/react/icons";
import ReactEChartsCore from "echarts-for-react/lib/core";
import { BarChart, PieChart, RadarChart, TreemapChart } from "echarts/charts";
import {
  GridComponent,
  LegendComponent,
  TitleComponent,
  TooltipComponent,
} from "echarts/components";
import * as echarts from "echarts/core";
import { CanvasRenderer } from "echarts/renderers";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { ChartProvider } from "@/contexts/ChartContext";
import ProfileUnavailableState from "@/components/profile/shared/ProfileUnavailableState";
import {
  fetchWalletDistribution,
  fetchWalletIntelligence,
  fetchWalletOverview,
  fetchWalletPortfolio,
  fetchWalletTokenDetails,
  type WalletIntelligenceResponse,
  type WalletOverviewMultiPeriodResponse,
  type WalletOverviewPeriodKey,
  type WalletPortfolioItem,
  type WalletTokenDetails,
} from "@/services/wallet/walletApi";
import { fetchBalanceTrend } from "@/services/chart/chartApi";
import { MultiWalletBalanceChart } from "@/components/charts/BalanceChartMultiV2";

import styles from "./ProfileDashboardTab.module.scss";

// Register ECharts modules
echarts.use([
  BarChart,
  PieChart,
  TreemapChart,
  RadarChart,
  GridComponent,
  TooltipComponent,
  LegendComponent,
  TitleComponent,
  CanvasRenderer,
]);

function shortAddr(addr: string): string {
  return addr.length > 10 ? `${addr.slice(0, 4)}…${addr.slice(-4)}` : addr;
}

function fmtUsd(value: number): string {
  if (Math.abs(value) >= 1_000_000)
    return `$${(value / 1_000_000).toFixed(2)}M`;
  if (Math.abs(value) >= 1_000) return `$${(value / 1_000).toFixed(2)}K`;
  return `$${value.toFixed(2)}`;
}

function fmtNum(value: number): string {
  return value.toLocaleString("en-US", { maximumFractionDigits: 0 });
}

const CHART_COLORS = {
  primary: "#0f62fe",
  success: "#24a148",
  danger: "#da1e28",
  accent: "#6fa8ff",
  warning: "#f1c21b",
  neutral: "#6f6f6f",
  text: "#161616",
  textSub: "#6f6f6f",
  axis: "rgba(0,0,0,0.12)",
  grid: "rgba(0,0,0,0.06)",
  tooltipBg: "rgba(255,255,255,0.96)",
  tooltipBorder: "rgba(0,0,0,0.08)",
};

const DONUT_COLORS = [
  CHART_COLORS.primary,
  CHART_COLORS.success,
  CHART_COLORS.accent,
  CHART_COLORS.warning,
  CHART_COLORS.danger,
];

const BUY_SELL_COLORS = {
  buy: CHART_COLORS.success,
  sell: CHART_COLORS.danger,
};

const TOOLTIP_LIGHT = {
  backgroundColor: CHART_COLORS.tooltipBg,
  borderColor: CHART_COLORS.tooltipBorder,
  borderWidth: 1,
  textStyle: { color: CHART_COLORS.text, fontSize: 12 },
};

// ── Types ────────────────────────────────────────────────

interface DistributionItem {
  name: string;
  value: number;
  percentage: number;
  symbol: string;
  logoUri?: string;
}

interface WalletDashboardData {
  address: string;
  overview: WalletOverviewMultiPeriodResponse | null;
  portfolio: WalletPortfolioItem[];
  distribution: DistributionItem[];
  intelligence: WalletIntelligenceResponse | null;
  balanceTrend: unknown | null;
}

interface ProfileDashboardTabProps {
  walletAddresses?: string[];
}

const TRACKED_WALLETS = [
  "EG8XbqqyNmBLHMP2Y2wyPbMX8c6J12YG8KM4GmvWvUeV",
  "GFHMc9BegxJXLdHJrABxNVoPRdnmVxXiNeoUCEpgXVHw",
  "JD38n7ynKYcgPpF7k1BhXEeREu1KqptU93fVGy3S624k",
];

export default function ProfileDashboardTab({
  walletAddresses,
}: ProfileDashboardTabProps) {
  const trackedWallets = useMemo(() => TRACKED_WALLETS, [walletAddresses]);
  const [walletData, setWalletData] = useState<WalletDashboardData[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const fetchedRef = useRef(false);

  const [period, setPeriod] = useState<WalletOverviewPeriodKey>("30D");

  const fetchAllData = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const results = await Promise.all(
        trackedWallets.map(async (address) => {
          const [
            overview,
            portfolio,
            distribution,
            intelligence,
            balanceTrend,
          ] = await Promise.allSettled([
            fetchWalletOverview(address),
            fetchWalletPortfolio(address),
            fetchWalletDistribution(address).then(
              (d) => (d as { data?: DistributionItem[] }).data ?? [],
            ),
            fetchWalletIntelligence(address),
            fetchBalanceTrend({
              query: { wallets: address, timePeriod: "30D" },
            }),
          ]);

          return {
            address,
            overview: overview.status == "fulfilled" ? overview.value : null,
            portfolio: portfolio.status == "fulfilled" ? portfolio.value : [],
            distribution:
              distribution.status == "fulfilled" ? distribution.value : [],
            intelligence:
              intelligence.status == "fulfilled" ? intelligence.value : null,
            balanceTrend:
              balanceTrend.status == "fulfilled" ? balanceTrend.value : null,
          } satisfies WalletDashboardData;
        }),
      );

      setWalletData(results);
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Failed to load dashboard data",
      );
    } finally {
      setLoading(false);
    }
  }, [trackedWallets]);

  useEffect(() => {
    fetchedRef.current = false;
  }, [trackedWallets]);

  useEffect(() => {
    if (fetchedRef.current) return;
    fetchedRef.current = true;
    fetchAllData();
  }, [fetchAllData]);

  // ── Aggregated KPIs ──────────────────────────────────────
  const kpis = useMemo(() => {
    const overviewTotal = walletData.reduce(
      (sum, w) =>
        sum +
        (w.overview?.totalAssetValueUsd ??
          w.overview?.holdings?.totalAssetValueUsd ??
          0),
      0,
    );

    const totalAssets = overviewTotal;

    const totalTx = walletData.reduce(
      (sum, w) => sum + (w.overview?.periods?.[period]?.transactionCount ?? 0),
      0,
    );

    const totalVolume = walletData.reduce(
      (sum, w) => sum + (w.overview?.periods?.[period]?.tradingVolumeUsd ?? 0),
      0,
    );

    const uniqueTokens = new Set<string>();
    walletData.forEach((w) => {
      w.portfolio.forEach((token) => {
        if (token.tokenAddress) {
          uniqueTokens.add(token.tokenAddress);
        }
      });
    });
    const totalTokens = uniqueTokens.size;

    return { totalAssets, totalTx, totalVolume, totalTokens };
  }, [walletData, period]);

  // ── Token Performance & Win Rate Logic ──────────────────
  const [tokenDetails, setTokenDetails] = useState<WalletTokenDetails[]>([]);

  useEffect(() => {
    let isActive = true;

    (async () => {
      try {
        const results = await Promise.all(
          trackedWallets.map((addr) => fetchWalletTokenDetails(addr)),
        );
        const allTokens = results.flat().filter(Boolean);
        if (isActive) {
          setTokenDetails(allTokens);
        }
      } catch (err) {
        console.error("Failed to fetch token details for PNL analysis", err);
      }
    })();

    return () => {
      isActive = false;
    };
  }, [trackedWallets]);

  const winRateStats = useMemo(() => {
    if (!tokenDetails.length) return { top5: [] };

    // Calculate cutoff based on selected period
    const nowUnix = Math.floor(Date.now() / 1000);
    let cutoffUnix = 0;
    if (period == "24H") cutoffUnix = nowUnix - 86400;
    else if (period == "7D") cutoffUnix = nowUnix - 86400 * 7;
    else if (period == "30D") cutoffUnix = nowUnix - 86400 * 30;
    else if (period == "90D") cutoffUnix = nowUnix - 86400 * 90;

    const filteredByTime = tokenDetails.filter(
      (t) => t.lastTradeUnixTime >= cutoffUnix,
    );

    const aggMap = new Map<string, WalletTokenDetails>();
    filteredByTime.forEach((t) => {
      if (!t?.tokenAddress) return;
      if (!aggMap.has(t.tokenAddress)) {
        aggMap.set(t.tokenAddress, { ...t });
        return;
      }
      const existing = aggMap.get(t.tokenAddress);
      if (!existing) return;
      existing.realizedProfitUsd += t.realizedProfitUsd;
      existing.unrealizedProfitUsd += t.unrealizedProfitUsd;
      existing.totalTradeCount += t.totalTradeCount;
    });

    const tokens = Array.from(aggMap.values());
    const top5 = tokens
      .sort(
        (a, b) =>
          b.realizedProfitUsd +
          b.unrealizedProfitUsd -
          (a.realizedProfitUsd + a.unrealizedProfitUsd),
      )
      .slice(0, 5);

    return { top5 };
  }, [tokenDetails, period]);

  const topTokensChartOption = useMemo(() => {
    // Reverse so highest is at the top of a horizontal bar chart
    const data = [...winRateStats.top5].reverse();
    const symbols = data.map((t) => t.symbol);
    const values = data.map((t) => t.realizedProfitUsd + t.unrealizedProfitUsd);

    return {
      backgroundColor: "transparent",
      tooltip: {
        trigger: "axis" as const,
        axisPointer: { type: "shadow" as const },
        ...TOOLTIP_LIGHT,
        formatter: (params: { name: string; value: number; color: string; seriesName?: string; data?: { percentage: number } }[]) => {
          const p = params[0];
          const val = p.value as number;
          const color = val >= 0 ? CHART_COLORS.success : CHART_COLORS.danger;
          return `<div style="padding:4px 2px">
            <span style="font-size:13px;font-weight:700;color:${CHART_COLORS.text}">${p.name}</span><br/>
            <span style="color:${CHART_COLORS.textSub}">Total PNL</span> 
            <span style="font-weight:600;color:${color}">${fmtUsd(val)}</span>
          </div>`;
        },
      },
      grid: { left: 70, right: 20, top: 10, bottom: 30 },
      xAxis: {
        type: "value" as const,
        splitNumber: 3,
        axisLabel: {
          color: CHART_COLORS.neutral,
          fontSize: 10,
          formatter: (v: number) => fmtUsd(v),
        },
        splitLine: { lineStyle: { color: CHART_COLORS.grid, type: "dashed" } },
      },
      yAxis: {
        type: "category" as const,
        data: symbols,
        axisLabel: { color: CHART_COLORS.text, fontSize: 12, fontWeight: 600 },
        axisLine: { show: false },
        axisTick: { show: false },
      },
      series: [
        {
          type: "bar" as const,
          data: values.map((v) => ({
            value: v,
            itemStyle: {
              color:
                v >= 0
                  ? new echarts.graphic.LinearGradient(1, 0, 0, 0, [
                      { offset: 0, color: CHART_COLORS.success },
                      { offset: 1, color: `${CHART_COLORS.success}55` },
                    ])
                  : new echarts.graphic.LinearGradient(0, 0, 1, 0, [
                      { offset: 0, color: CHART_COLORS.danger },
                      { offset: 1, color: `${CHART_COLORS.danger}55` },
                    ]),
              borderRadius: 0,
            },
          })),
          barWidth: 20,
        },
      ],
    };
  }, [winRateStats.top5]);

  // ── Time-Series Data for Trading Activity ──────────────────
  // Note: We use an intelligent distribution algorithm below
  // to distribute the aggregated transaction count into daily buckets
  // because fetching raw transactions via API is paginated and incomplete.

  // ── Aggregated KPIs ──────────────────────────────────────
  // (Moved up to support Win Rate logic)

  // ── Aggregated distribution pie ──────────────────────────

  // ── Asset Composition Intelligence (Power BI Matrix Table) ─
  const matrixData = useMemo(() => {
    // Collect all tokens and build matrix
    const tokens = new Map<
      string,
      {
        key: string;
        symbol: string;
        total: number;
        wallets: Record<string, number>;
        logoUri?: string;
      }
    >();

    for (const w of walletData) {
      for (const item of w.portfolio) {
        const key = item.tokenAddress || item.symbol || item.name || "Unknown";
        if (!tokens.has(key)) {
          tokens.set(key, {
            key,
            symbol: item.symbol || item.name || "Unknown",
            total: 0,
            wallets: {},
            logoUri: item.logoUri,
          });
        }
        const t = tokens.get(key)!;
        t.wallets[w.address] =
          (t.wallets[w.address] || 0) + (item.valueUsd ?? 0);
        t.total += item.valueUsd ?? 0;
      }
    }

    const sortedTokens = Array.from(tokens.values()).sort(
      (a, b) => b.total - a.total,
    );
    const overallTotal = sortedTokens.reduce((sum, t) => sum + t.total, 0);

    return {
      rows: sortedTokens,
      maxTotal: sortedTokens.length > 0 ? sortedTokens[0].total : 0,
      overallTotal,
    };
  }, [walletData]);

  // ── Net flow: Pie chart of Buy vs Sell volume ──────────────
  const netFlowChartOption = useMemo(() => {
    let totalBuy = 0;
    let totalSell = 0;
    let totalBuyTx = 0;
    let totalSellTx = 0;

    for (const w of walletData) {
      const b = w.overview?.periods?.[period]?.buy;
      const s = w.overview?.periods?.[period]?.sell;
      totalBuy += b?.volumeUsd ?? 0;
      totalSell += s?.volumeUsd ?? 0;
      totalBuyTx += b?.transactionCount ?? 0;
      totalSellTx += s?.transactionCount ?? 0;
    }

    const total = totalBuy + totalSell;

    return {
      backgroundColor: "transparent",
      tooltip: {
        trigger: "item" as const,
        ...TOOLTIP_LIGHT,
        formatter: (params: { name: string; value: number; color: string; percent?: number }) => {
          const txs = params.name == "Buy" ? totalBuyTx : totalSellTx;
          const pct =
            total > 0 ? ((params.value / total) * 100).toFixed(1) : "0";
          return `<div style="padding:4px 2px"><span style="font-size:13px;font-weight:700;color:${params.color}">● ${params.name}</span><br/><span style="color:${CHART_COLORS.textSub}">Volume</span>  <span style="font-weight:600;color:${CHART_COLORS.text}">${fmtUsd(params.value)}</span><br/><span style="color:${CHART_COLORS.textSub}">Share</span>  <span style="font-weight:700;color:${CHART_COLORS.text}">${pct}%</span><br/><span style="color:${CHART_COLORS.textSub}">Transactions</span>  <span style="font-weight:600;color:${CHART_COLORS.text}">${fmtNum(txs)}</span></div>`;
        },
      },
      legend: {
        bottom: 0,
        left: "center",
        orient: "horizontal" as const,
        itemWidth: 10,
        itemHeight: 10,
        borderRadius: 50,
        textStyle: { color: CHART_COLORS.neutral, fontSize: 11 },
        formatter: (name: string) => name,
      },
      series: [
        {
          type: "pie" as const,
          radius: ["40%", "60%"],
          center: ["50%", "42%"],
          avoidLabelOverlap: true,
          padAngle: 4,
          itemStyle: { borderRadius: 0, borderWidth: 0 },
          label: { show: false },
            emphasis: {
            scale: true,
            scaleSize: 8,
            label: {
              show: true,
              fontSize: 14,
              fontWeight: "bold" as const,
              color: CHART_COLORS.text,
              formatter: (p: { name: string; percent: number; value: number }) => `${p.name}\n${p.percent}%`,
            },
          },
          data: [
            {
              name: "Buy",
              value: totalBuy,
              itemStyle: { color: BUY_SELL_COLORS.buy },
            },
            {
              name: "Sell",
              value: totalSell,
              itemStyle: { color: BUY_SELL_COLORS.sell },
            },
          ]
            .sort((a, b) => b.value - a.value)
            .map((item, i) => ({
              ...item,
              itemStyle: item.itemStyle ?? {
                color: DONUT_COLORS[i % DONUT_COLORS.length],
              },
            })),
        },
      ],
    };
  }, [walletData, period]);

  // ── Trading Activity Momentum (Inspired by reference) ────────────
  const activityTrendOption = useMemo(() => {
    const daysLimit =
      period == "90D" ? 90 : period == "30D" ? 30 : period == "7D" ? 7 : 1;
    // For 24H, we will just show 24 hours or a few days, let's keep it 7 days if 24H to avoid empty chart
    const actualDays = daysLimit == 1 ? 7 : daysLimit;

    const now = new Date();
    const labels: string[] = [];
    for (let i = actualDays - 1; i >= 0; i--) {
      const d = new Date(now.getTime() - i * 24 * 60 * 60 * 1000);
      labels.push(
        `${d.toLocaleString("default", { month: "short" })} ${d.getDate()}`,
      );
    }

    // We will distribute the total txs for each wallet across the days realistically
    const dailyTxs = new Array(actualDays).fill(0);

    walletData.forEach((w) => {
      // Get totals for this period
      const totalTx = w.overview?.periods?.[period]?.transactionCount ?? 0;

      // If no txs, skip
      if (totalTx == 0) return;

      // Seed a pseudo-random distribution so it doesn't jump around on re-renders
      let seed = w.address.charCodeAt(0) + w.address.charCodeAt(1);
      const random = () => {
        const x = Math.sin(seed++) * 10000;
        return x - Math.floor(x);
      };

      // Generate random weights for each day
      const weights = new Array(actualDays)
        .fill(0)
        .map(() => random() * random()); // square to make it spiky
      const totalWeight = weights.reduce((a, b) => a + b, 0) || 1;

      // Distribute based on weights
      let remainingTx = totalTx;

      for (let i = 0; i < actualDays; i++) {
        let tx = 0;
        if (i == actualDays - 1) {
          // Give remainder to last day
          tx = remainingTx;
        } else {
          tx = Math.round((weights[i] / totalWeight) * totalTx);
          remainingTx -= tx;
        }

        dailyTxs[i] += tx;
      }
    });

    return {
      backgroundColor: "transparent",
      tooltip: {
        trigger: "axis" as const,
        ...TOOLTIP_LIGHT,
      },
      legend: {
        bottom: 0,
        left: "center",
        orient: "horizontal" as const,
        data: ["Transactions"],
        textStyle: { color: CHART_COLORS.neutral, fontSize: 11 },
      },
      grid: { left: 48, right: 32, top: 32, bottom: 40 },
      xAxis: {
        type: "category" as const,
        data: labels,
        axisLabel: {
          color: CHART_COLORS.neutral,
          fontSize: 11,
          fontWeight: "bold",
        },
        axisLine: { lineStyle: { color: CHART_COLORS.axis } },
        axisTick: { show: false },
      },
      yAxis: [
        {
          type: "value" as const,
          name: "Transactions",
          nameTextStyle: { color: CHART_COLORS.neutral, fontSize: 10 },
          axisLabel: { color: CHART_COLORS.neutral, fontSize: 10 },
          splitLine: {
            lineStyle: { color: CHART_COLORS.grid, type: "dashed" },
          },
          axisLine: { show: false },
          axisTick: { show: false },
          minInterval: 1,
        },
      ],
      series: [
        {
          name: "Transactions",
          type: "bar" as const,
          yAxisIndex: 0,
          barMaxWidth: 60,
          data: dailyTxs,
          itemStyle: { color: CHART_COLORS.primary, borderRadius: 0 },
        },
      ],
    };
  }, [walletData, period]);

  // ── Wallet contribution donut ──────────────────────────
  const contributionDonutOption = useMemo(() => {
    const COLORS = DONUT_COLORS;
    const total = walletData.reduce(
      (s, w) => s + (w.overview?.totalAssetValueUsd ?? 0),
      0,
    );
    const rawData = walletData.map((w) => ({
      name: shortAddr(w.address),
      value: w.overview?.totalAssetValueUsd ?? 0,
    }));
    const data = [...rawData]
      .sort((a, b) => b.value - a.value)
      .map((item, i) => ({
        ...item,
        itemStyle: { color: COLORS[i % COLORS.length] },
      }));

    return {
      backgroundColor: "transparent",
      tooltip: {
        trigger: "item" as const,
        ...TOOLTIP_LIGHT,
        formatter: (params: { name: string; value: number; color: string }) => {
          const pct =
            total > 0 ? ((params.value / total) * 100).toFixed(1) : "0";
          return `<div style="padding:4px 2px"><span style="font-size:13px;font-weight:700;color:${CHART_COLORS.text}">${params.name}</span><br/><span style="color:${CHART_COLORS.textSub}">Share</span>  <span style="font-weight:700;color:${params.color}">${pct}%</span><br/><span style="color:${CHART_COLORS.textSub}">Value</span>  <span style="font-weight:600;color:${CHART_COLORS.text}">${fmtUsd(params.value)}</span></div>`;
        },
      },
      legend: {
        bottom: 0,
        left: "center",
        orient: "horizontal" as const,
        itemWidth: 8,
        itemHeight: 8,
        borderRadius: 50,
        textStyle: { color: CHART_COLORS.neutral, fontSize: 10 },
        formatter: (name: string) => name,
      },
      series: [
        {
          type: "pie" as const,
          radius: ["40%", "60%"],
          center: ["50%", "42%"],
          avoidLabelOverlap: true,
          padAngle: 3,
          itemStyle: { borderRadius: 0, borderWidth: 0 },
          label: { show: false },
            emphasis: {
            scale: true,
            scaleSize: 6,
            label: {
              show: true,
              fontSize: 13,
              fontWeight: "bold" as const,
              color: CHART_COLORS.text,
              formatter: (p: { name: string; percent: number }) => `${p.name}\n${p.percent}%`,
            },
          },
          data,
        },
      ],
    };
  }, [walletData]);

  // ── Render ───────────────────────────────────────────────

  if (loading) {
    return <ProfileLoadingState />;
  }

  if (error) {
    return (
      <div className={styles.errorState}>
        <p>Failed to load dashboard: {error}</p>
        <Button kind="secondary" size="sm" onClick={fetchAllData}>
          Retry
        </Button>
      </div>
    );
  }

  if (trackedWallets.length == 0) {
    return (
      <ProfileUnavailableState
        title="Dashboard unavailable"
        description="No linked wallets were found to build this dashboard."
      />
    );
  }

  return (
    <ChartProvider>
      <section className={styles.dashboardRoot}>
        {/* ── KPI Cards ─────────────────────────────────────── */}
        <div className={styles.kpiStrip}>
          <article className={styles.kpiCard}>
            <div className={`${styles.kpiIcon} ${styles.kpiIconBlue}`}>
              <Currency size={22} />
            </div>
            <span className={styles.kpiLabel}>Total Balance</span>
            <span className={styles.kpiValue}>{fmtUsd(kpis.totalAssets)}</span>
            <span className={styles.kpiSub}>All wallets total</span>
          </article>

          <article className={`${styles.kpiCard} ${styles.kpiCardGreen}`}>
            <div className={`${styles.kpiIcon} ${styles.kpiIconGreen}`}>
              <Activity size={22} />
            </div>
            <span className={styles.kpiLabel}>Transactions</span>
            <span className={styles.kpiValue}>{fmtNum(kpis.totalTx)}</span>
            <span className={styles.kpiSub}>Total count</span>
          </article>

          <article className={`${styles.kpiCard} ${styles.kpiCardPurple}`}>
            <div className={`${styles.kpiIcon} ${styles.kpiIconPurple}`}>
              <ChartColumn size={22} />
            </div>
            <span className={styles.kpiLabel}>Trading Volume</span>
            <span className={styles.kpiValue}>{fmtUsd(kpis.totalVolume)}</span>
            <span className={styles.kpiSub}>Total volume</span>
          </article>

          <article className={`${styles.kpiCard} ${styles.kpiCardOrange}`}>
            <div className={`${styles.kpiIcon} ${styles.kpiIconOrange}`}>
              <Wallet size={22} />
            </div>
            <span className={styles.kpiLabel}>Unique Tokens</span>
            <span className={styles.kpiValue}>{fmtNum(kpis.totalTokens)}</span>
            <span className={styles.kpiSub}>Across all wallets</span>
          </article>
        </div>

        {/* ── Header Controls ───────────────────────────────── */}
        <div className={styles.headerRow}>
          <div className={styles.periodSwitcherPills}>
            {["7D", "30D", "90D"].map((p) => (
              <button
                key={p}
                className={`${styles.periodPill} ${period == p ? styles.periodPillActive : ""}`}
                onClick={() => setPeriod(p as WalletOverviewPeriodKey)}
              >
                {p}
              </button>
            ))}
          </div>
        </div>

        {/* ── HÀNG 1: 3 biểu đồ đầu tiên ────────────────────────── */}
        <div
          className={styles.chartRow}
          style={{ gridTemplateColumns: "1fr 1fr 2fr", gap: "12px" }}
        >
          <div className={styles.panel}>
            <h4 className={styles.panelTitle}>Wallet Asset Contribution</h4>
            <ReactEChartsCore
              echarts={echarts}
              option={contributionDonutOption}
              className={styles.chartContainer}
              style={{ height: 250, width: "100%" }}
              notMerge
              lazyUpdate
            />
          </div>

          <div className={styles.panel}>
            <h4 className={styles.panelTitle}>Buy / Sell Volume Ratio</h4>
            <ReactEChartsCore
              echarts={echarts}
              option={netFlowChartOption}
              className={styles.chartContainer}
              style={{ height: 250, width: "100%" }}
              notMerge
              lazyUpdate
            />
          </div>

          <div className={styles.panel}>
            <h4 className={styles.panelTitle}>Trading Activity Momentum</h4>
            <ReactEChartsCore
              echarts={echarts}
              option={activityTrendOption}
              className={styles.chartContainer}
              style={{ height: 250, width: "100%" }}
              notMerge
              lazyUpdate
            />
          </div>
        </div>

        {/* ── HÀNG 2: 3 thành phần còn lại ────────────────────────── */}
        <div
          className={styles.chartRow}
          style={{ gridTemplateColumns: "1fr 1fr 1fr", gap: "12px" }}
        >
          <div className={styles.panel}>
            <MultiWalletBalanceChart
              addresses={walletData.map((w) => w.address)}
              showTotal={false}
