export const SolanaProvider: FC<SolanaProviderProps> = ({ children }) => {
  /**
   * Derive the network from VITE_SOLANA_NETWORK with strict validation.
   * Falls back to Devnet if the env is misconfigured so the UI can still
   * mount and display the error through its own toast/alert system.
   */
  const network = useMemo((): WalletAdapterNetwork => {
    try {
      return getWalletAdapterNetwork();
    } catch (err) {
      console.error(
        "[SolanaProvider] Network configuration error — falling back to Devnet:\n",
        (err as Error).message
      );
      return WalletAdapterNetwork.Devnet;
    }
  }, []);
  const endpoint = useMemo(() => {
    try {
      return getSolanaRpcEndpoint();
    } catch (err) {
      console.error(
        "[SolanaProvider] RPC configuration error — falling back to clusterApiUrl:\n",
        (err as Error).message
      );
      return clusterApiUrl(network);
    }
  }, [network]);

  const wallets = useMemo(
    () => [new PhantomWalletAdapter(), new SolflareWalletAdapter({ network })],
    [network],
  );

  localStorage.removeItem("walletName");

  return (
    <ConnectionProvider endpoint={endpoint}>
      <WalletProvider wallets={wallets} autoConnect={false}>
        <WalletModalProvider
          container="#wallet-modal-container"
          className="hello"
        >
          <SolanaProviderContent>{children}</SolanaProviderContent>
        </WalletModalProvider>
      </WalletProvider>
    </ConnectionProvider>
  );
};

import { THEME_LOCAL_STORAGE_KEY } from "@/config/constants";
import { GlobalTheme, Theme } from "@carbon/react";
import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
  type ComponentProps,
  type ReactNode,
  type RefObject,
} from "react";

type SupportedTheme = ComponentProps<typeof Theme>["theme"];
const userThemes = {
  light: "white",
  dark: "g100",
} as const satisfies Record<string, SupportedTheme>;
export type ThemeMode = keyof typeof userThemes;

function isValidTheme(value: string): value is ThemeMode {
  return Object.keys(userThemes).includes(value);
}

interface ThemeContextType {
  theme: ThemeMode;
  toggleTheme: () => void;
  themeRef: RefObject<HTMLDivElement | null>;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

interface ThemeProviderProps {
  children: ReactNode;
}

function getInitialTheme(): ThemeMode {
  const previousTheme = localStorage.getItem(THEME_LOCAL_STORAGE_KEY);
  if (previousTheme && isValidTheme(previousTheme)) {
    return previousTheme;
  }
  return "light";
}

export const ThemeProvider: React.FC<ThemeProviderProps> = ({ children }) => {
  const [theme, setTheme] = useState<ThemeMode>(getInitialTheme);

  const themeRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem(THEME_LOCAL_STORAGE_KEY, theme);
  }, [theme]);

  const toggleTheme = useCallback(() => {
    setTheme((prevTheme) => (prevTheme == "light" ? "dark" : "light"));
  }, []);

  return (
    <ThemeContext.Provider
      value={{
        theme,
        toggleTheme,
        themeRef,
      }}
    >
      <GlobalTheme theme={userThemes[theme]}>
        <Theme theme={userThemes[theme]} style={{ minHeight: "100vh" }}>
          <div
            ref={themeRef}
            className="yoca-app-theme"
            data-carbon-theme
            data-yoca-theme={theme}
          >
            {children}
          </div>
        </Theme>
      </GlobalTheme>
    </ThemeContext.Provider>
  );
};

export function useUserTheme() {
  const context = useContext(ThemeContext);
  if (context == undefined) {
    throw new Error("useUserTheme must be used within a ThemeProvider");
  }
  return context;
}

import { useAuth } from "@/contexts/AuthContext";
import {
    addTokenToWatchlist,
    addWalletToWatchlist,
    getTokenWatchlist,
    getWalletWatchlist,
    removeTokenFromWatchlist,
    removeWalletFromWatchlist,
} from "@/services/profile/profileApi";
import {
    createContext,
    useCallback,
    useContext,
    useEffect,
    useMemo,
    useState,
    type ReactNode,
} from "react";

interface WatchlistContextType {
    tokenWatchlist: string[];
    walletWatchlist: string[];
    isLoading: boolean;
    tokenPending: Record<string, boolean>;
    walletPending: Record<string, boolean>;
    refetch: () => Promise<void>;
    addToken: (tokenAddress: string) => Promise<void>;
    removeToken: (tokenAddress: string) => Promise<void>;
    toggleToken: (tokenAddress: string) => Promise<void>;
    addWallet: (walletAddress: string) => Promise<void>;
    removeWallet: (walletAddress: string) => Promise<void>;
    toggleWallet: (walletAddress: string) => Promise<void>;
}

const WatchlistContext = createContext<WatchlistContextType | undefined>(
    undefined,
);

function pushUnique(items: string[], value: string): string[] {
    if (items.includes(value)) return items;
    return [...items, value];
}

function removeValue(items: string[], value: string): string[] {
    return items.filter((item) => item !== value);
}

export function WatchlistProvider({ children }: { children: ReactNode }) {
    const { user } = useAuth();
    const [tokenWatchlist, setTokenWatchlist] = useState<string[]>([]);
    const [walletWatchlist, setWalletWatchlist] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [tokenPending, setTokenPending] = useState<Record<string, boolean>>({});
    const [walletPending, setWalletPending] = useState<Record<string, boolean>>({});

    const refetch = useCallback(async () => {
        if (!user) {
            setTokenWatchlist([]);
            setWalletWatchlist([]);
            return;
        }

        setIsLoading(true);
        try {
            const [tokens, wallets] = await Promise.all([
                getTokenWatchlist(),
                getWalletWatchlist(),
            ]);
            setTokenWatchlist(tokens);
            setWalletWatchlist(wallets);
        } catch {
            setTokenWatchlist([]);
            setWalletWatchlist([]);
        } finally {
            setIsLoading(false);
        }
    }, [user]);

    useEffect(() => {
        void refetch();
    }, [refetch]);

    const addToken = useCallback(async (tokenAddress: string) => {
        setTokenPending((prev) => ({ ...prev, [tokenAddress]: true }));
        setTokenWatchlist((prev) => pushUnique(prev, tokenAddress));

        try {
            await addTokenToWatchlist(tokenAddress);
        } catch (error) {
            setTokenWatchlist((prev) => removeValue(prev, tokenAddress));
            throw error;
        } finally {
            setTokenPending((prev) => ({ ...prev, [tokenAddress]: false }));
        }
    }, []);

    const removeToken = useCallback(async (tokenAddress: string) => {
        setTokenPending((prev) => ({ ...prev, [tokenAddress]: true }));
        setTokenWatchlist((prev) => removeValue(prev, tokenAddress));

        try {
            await removeTokenFromWatchlist(tokenAddress);
        } catch (error) {
            setTokenWatchlist((prev) => pushUnique(prev, tokenAddress));
            throw error;
        } finally {
            setTokenPending((prev) => ({ ...prev, [tokenAddress]: false }));
        }
    }, []);

    const toggleToken = useCallback(
        async (tokenAddress: string) => {
            const exists = tokenWatchlist.includes(tokenAddress);
            if (exists) {
                await removeToken(tokenAddress);
                return;
            }
            await addToken(tokenAddress);
        },
        [addToken, removeToken, tokenWatchlist],
    );

    const addWallet = useCallback(async (walletAddress: string) => {
        setWalletPending((prev) => ({ ...prev, [walletAddress]: true }));
        setWalletWatchlist((prev) => pushUnique(prev, walletAddress));

        try {
            await addWalletToWatchlist(walletAddress);
        } catch (error) {
            setWalletWatchlist((prev) => removeValue(prev, walletAddress));
            throw error;
        } finally {
            setWalletPending((prev) => ({ ...prev, [walletAddress]: false }));
        }
    }, []);

    const removeWallet = useCallback(async (walletAddress: string) => {
        setWalletPending((prev) => ({ ...prev, [walletAddress]: true }));
        setWalletWatchlist((prev) => removeValue(prev, walletAddress));

        try {
            await removeWalletFromWatchlist(walletAddress);
        } catch (error) {
            setWalletWatchlist((prev) => pushUnique(prev, walletAddress));
            throw error;
        } finally {
            setWalletPending((prev) => ({ ...prev, [walletAddress]: false }));
        }
    }, []);

    const toggleWallet = useCallback(
        async (walletAddress: string) => {
            const exists = walletWatchlist.includes(walletAddress);
            if (exists) {
                await removeWallet(walletAddress);
                return;
            }
            await addWallet(walletAddress);
        },
        [addWallet, removeWallet, walletWatchlist],
    );

    const value = useMemo<WatchlistContextType>(
        () => ({
            tokenWatchlist,
            walletWatchlist,
            isLoading,
            tokenPending,
            walletPending,
            refetch,
            addToken,
            removeToken,
            toggleToken,
            addWallet,
            removeWallet,
            toggleWallet,
        }),
        [
            tokenWatchlist,
            walletWatchlist,
            isLoading,
            tokenPending,
            walletPending,
            refetch,
            addToken,
            removeToken,
            toggleToken,
            addWallet,
            removeWallet,
            toggleWallet,
        ],
    );

    return (
